export interface Theme {
  /** Main brand color — headings, highlights, active elements */
  primary: string
  /** Secondary brand color — interactive highlights, focused states */
  accent: string
  /** Tertiary color — user messages, checkboxes, prompts */
  secondary: string
  /** Subdued color — disabled states, secondary text, cursor */
  muted: string
  /** Placeholder text color */
  placeholder: string
  /** Border and divider color */
  border: string
  /** Muted border color — subtle structural dividers */
  borderMuted: string
  /** Default foreground text color */
  foreground: string
  /** App background color */
  background: string
  /** Success state color */
  success: string
  /** Error state color */
  error: string
  /** Warning state color */
  warning: string
  /** Bright focus color — component is selected (entered for interaction) */
  focusSelected: string
  /** Medium focus color — component has keyboard focus */
  focusFocused: string
  /** Dimmed focus color — idle hint that the component is selectable */
  focusIdle: string
  /** Background color for assistant message bubbles */
  messageAssistant: string
  /** Background color for user message bubbles */
  messageUser: string
}

export const darkTheme: Theme = {
  primary: "#FF71CE",
  accent: "#01CDFE",
  secondary: "#B967FF",
  muted: "#A69CBD",
  placeholder: "#CEC7DE",
  border: "#B967FF",
  borderMuted: "#2A2A2A",
  foreground: "#F0E6FF",
  background: "#0D0B10",
  success: "#05FFA1",
  error: "#FF6B6B",
  warning: "#FFC164",
  focusSelected: "#FF71CE",
  focusFocused: "#e065b8",
  focusIdle: "#33192a",
  messageAssistant: "#2a2a4a",
  messageUser: "#2a3a3a",
}

export const lightTheme: Theme = {
  primary: "#FF6B2B",
  accent: "#3B82F6",
  secondary: "#0369A1",
  muted: "#64748B",
  placeholder: "#475569",
  border: "#E2E8F0",
  borderMuted: "#D9D9D9",
  foreground: "#1E293B",
  background: "#FFFFFF",
  success: "#0B8438",
  error: "#E11D48",
  warning: "#B45309",
  focusSelected: "#FF6B2B",
  focusFocused: "#d45a24",
  focusIdle: "#f5e6d8",
  messageAssistant: "#F1F5F9",
  messageUser: "#E2E8F0",
}

import { createContext, useContext, type ReactNode } from "react"
const ThemeContext = createContext<Theme>(darkTheme)

export interface ThemeProviderProps {
  theme: Theme
  children: ReactNode
}

/** Provides a theme to all descendant components via React context. */
export function ThemeProvider({ theme, children }: ThemeProviderProps) {
  return <ThemeContext.Provider value={theme}>{children}</ThemeContext.Provider>
}

/** Returns the current theme from the nearest ThemeProvider. Falls back to darkTheme. */
export function useTheme(): Theme {
  return useContext(ThemeContext)
}

import { getFocusBorderStyle, getFocusDividerStyle } from "@gridland/utils"
import type { FocusBorderState, FocusBorderResult, FocusDividerResult } from "@gridland/utils"

/** Returns focus border color and style from the current theme. */
export function useFocusBorderStyle(state: FocusBorderState): FocusBorderResult {
  const theme = useTheme()
  return getFocusBorderStyle(state, {
    selected: theme.focusSelected,
    focused: theme.focusFocused,
    idle: theme.focusIdle,
  })
}

/** Returns focus divider color and dashed state from the current theme. */
export function useFocusDividerStyle(state: FocusBorderState): FocusDividerResult {
  const theme = useTheme()
  return getFocusDividerStyle(state, {
    selected: theme.focusSelected,
    focused: theme.focusFocused,
    idle: theme.focusIdle,
  })
}

import { createContext, useContext } from "react"
import type { ReactNode } from "react"
import type { Theme } from "./theme"
import { darkTheme } from "./theme"
import { ThemeProvider } from "./theme"

type KeyboardHandler = (event: any) => void
type UseKeyboardHook = (handler: KeyboardHandler) => void

const KeyboardContext = createContext<UseKeyboardHook | null>(null)

export interface GridlandProviderProps {
  /** Theme object. Defaults to darkTheme. */
  theme?: Theme
  /** Keyboard hook from @opentui/react. Provided once here so components don't need it as a prop. */
  useKeyboard?: UseKeyboardHook
  children: ReactNode
}

/** Root provider that supplies theme and keyboard context to all Gridland components. */
export function GridlandProvider({ theme, useKeyboard, children }: GridlandProviderProps) {
  const inner = (
    <KeyboardContext.Provider value={useKeyboard ?? null}>
      {children}
    </KeyboardContext.Provider>
  )

  // Only wrap with ThemeProvider if a theme is explicitly provided
  if (theme) {
    return <ThemeProvider theme={theme}>{inner}</ThemeProvider>
  }

  return inner
}

/**
 * Returns the useKeyboard hook from context, or the prop override if provided.
 * Components should call this instead of using the prop directly.
 */
export function useKeyboardContext(propOverride?: UseKeyboardHook): UseKeyboardHook | undefined {
  const fromContext = useContext(KeyboardContext)
  return propOverride ?? fromContext ?? undefined
}

import { useTerminalDimensions } from "@gridland/utils"

export interface Breakpoints {
  /** Width < 40 columns */
  isTiny: boolean
  /** Width < 60 columns */
  isNarrow: boolean
  /** Width < 70 columns */
  isMobile: boolean
  /** Width >= 70 columns */
  isDesktop: boolean
  /** Terminal width in columns */
  width: number
  /** Terminal height in rows */
  height: number
}

export const BREAKPOINTS = {
  tiny: 40,
  narrow: 60,
  mobile: 70,
} as const

/** Returns responsive breakpoint flags based on current terminal dimensions. */
export function useBreakpoints(): Breakpoints {
  const { width, height } = useTerminalDimensions()

  return {
    isTiny: width < BREAKPOINTS.tiny,
    isNarrow: width < BREAKPOINTS.narrow,
    isMobile: width < BREAKPOINTS.mobile,
    isDesktop: width >= BREAKPOINTS.mobile,
    width,
    height,
  }
}

import { useTheme } from "./theme"

export interface AsciiProps {
  /** The text string to render as ASCII art. */
  text: string
  /** Font variant for the ASCII rendering. */
  font?: "tiny" | "block" | "slick" | "shade"
  /** Override the text color. Defaults to theme.primary. */
  color?: string
}

/** Renders text as ASCII art using the specified font and color. */
export function Ascii({ text, font, color }: AsciiProps) {
  const theme = useTheme()
  const resolvedColor = color ?? theme.primary
  return <ascii-font text={text} font={font} style={{ fg: resolvedColor }} />
}

import { textStyle } from "./text-style"
import { useTheme } from "./theme"
import type { Theme } from "./theme"
import { PromptInput } from "./prompt-input"
import type { ChatStatus } from "./prompt-input"

export interface ChatMessage {
  /** Unique identifier for the message. Used as a list key. */
  id: string
  /** Determines the prefix character and color. */
  role: "user" | "assistant"
  /** The message text content. */
  content: string
  /** Tool calls associated with this message (accepted but not rendered inline). */
  toolCalls?: ToolCallInfo[]
}

export interface ToolCallInfo {
  /** Unique identifier for the tool call. Used as a list key. */
  id: string
  /** Display name/description of the tool call. */
  title: string
  /** Current status, determines the icon and color. */
  status: "pending" | "in_progress" | "completed" | "failed"
  /** Result text from the tool call (accepted but not displayed). */
  result?: string
}

export interface ChatPanelProps {
  /** Array of messages to display. */
  messages: ChatMessage[]
  /** Partial text being streamed from the assistant. */
  streamingText?: string
  /**
   * AI chat status — drives loading/streaming/error states.
   * When provided, takes precedence over `isLoading`.
   * - `ready`: input enabled
   * - `submitted`: shows loading indicator, input disabled
   * - `streaming`: shows streaming text, input disabled, Esc calls onStop
   * - `error`: input enabled, shows error state
   */
  status?: ChatStatus
  /** Whether the assistant is processing. Ignored when `status` is provided. */
  isLoading?: boolean
  /** Currently active tool calls to display as status cards. */
  activeToolCalls?: ToolCallInfo[]
  /** Callback fired when the user submits a message. */
  onSendMessage: (text: string) => void
  /** Callback to stop generation. Wired to Escape key during streaming. */
  onStop?: () => void
  /** Callback for cancellation. Wired to Escape key when loading/streaming. @deprecated Use `onStop` instead. */
  onCancel?: () => void
  /** Placeholder text shown in the input when empty. */
  placeholder?: string
  /** The prompt string shown before user input. */
  promptChar?: string
  /** Color of the prompt character in the input. */
  promptColor?: string
  /** Color of the > prefix on user messages. */
  userColor?: string
  /** Color of the < prefix on assistant messages and streaming text. */
  assistantColor?: string
  /** Text displayed when loading (and not streaming). */
  loadingText?: string
  /** Whether the input is focused and accepting keystrokes */
  focus?: boolean
  /** Keyboard handler — pass useKeyboard from @opentui/react */
  useKeyboard?: (handler: (event: any) => void) => void
}

const STATUS_ICONS: Record<string, string> = {
  pending: "\u2022",
  in_progress: "\u280B",
  completed: "\u2713",
  failed: "\u2717",
}

function getStatusColors(theme: Theme): Record<string, string> {
  return {
    pending: theme.muted,
    in_progress: theme.warning,
    completed: theme.success,
    failed: theme.error,
  }
}

function MessageBubble({
  message,
  userColor,
  assistantColor,
  foregroundColor,
}: {
  message: ChatMessage
  userColor: string
  assistantColor: string
  foregroundColor: string
}) {
  const isUser = message.role === "user"
  const prefix = isUser ? "> " : "< "
  const color = isUser ? userColor : assistantColor

  return (
    <text wrapMode="word">
      <span style={textStyle({ bold: true, fg: color })}>{prefix}</span>
      <span style={{ fg: foregroundColor }}>{message.content}</span>
    </text>
  )
}

function StreamingTextDisplay({
  text,
  assistantColor,
  foregroundColor,
  cursorChar = "_",
}: {
  text: string
  assistantColor: string
  foregroundColor: string
  cursorChar?: string
}) {
  if (!text) return null

  return (
    <text wrapMode="word">
      <span style={textStyle({ bold: true, fg: assistantColor })}>{"< "}</span>
      <span style={{ fg: foregroundColor }}>{text}</span>
      <span style={textStyle({ dim: true, fg: foregroundColor })}>{cursorChar}</span>
    </text>
  )
}

function ToolCallCard({ toolCall, statusColors }: { toolCall: ToolCallInfo; statusColors: Record<string, string> }) {
  const icon = STATUS_ICONS[toolCall.status] || "\u2022"
  const color = statusColors[toolCall.status] || "gray"
  const showEllipsis = toolCall.status === "pending" || toolCall.status === "in_progress"

  return (
    <text>
      <span>{"  "}</span>
      <span style={textStyle({ fg: color })}>{icon}</span>
      <span>{" "}</span>
      <span style={textStyle({ fg: color })}>{toolCall.title}</span>
      {showEllipsis && <span style={textStyle({ dim: true, fg: color })}>{" ..."}</span>}
    </text>
  )
}

/** Vertical chat interface with message history, tool call cards, streaming text, and input. */
export function ChatPanel({
  messages,
  streamingText = "",
  status,
  isLoading = false,
  activeToolCalls = [],
  onSendMessage,
  onStop,
  onCancel,
  placeholder = "Type a message...",
  promptChar = "> ",
  promptColor,
  userColor,
  assistantColor,
  loadingText = "Thinking...",
  focus,
  useKeyboard: useKeyboardProp,
}: ChatPanelProps) {
  const theme = useTheme()
  const resolvedUserColor = userColor ?? theme.secondary
  const resolvedAssistantColor = assistantColor ?? theme.primary
  const resolvedPromptColor = promptColor ?? theme.secondary
  const statusColors = getStatusColors(theme)

  // Derive chat status from props
  const chatStatus: ChatStatus | undefined = status
    ? status
    : isLoading && !streamingText ? "submitted"
    : streamingText ? "streaming"
    : undefined

  const isSubmitted = chatStatus === "submitted"
  const isStreaming = chatStatus === "streaming"
  const stopHandler = onStop ?? onCancel

  return (
    <box flexDirection="column" paddingX={1}>
      {/* Messages */}
      {messages.map((msg) => (
        <MessageBubble
          key={msg.id}
          message={msg}
          userColor={resolvedUserColor}
          assistantColor={resolvedAssistantColor}
          foregroundColor={theme.foreground}
        />
      ))}

      {/* Tool call cards */}
      {activeToolCalls.map((tc) => (
        <ToolCallCard key={tc.id} toolCall={tc} statusColors={statusColors} />
      ))}

      {/* Streaming text OR loading indicator */}
      {isStreaming && streamingText ? (
        <StreamingTextDisplay
          text={streamingText}
          assistantColor={resolvedAssistantColor}
          foregroundColor={theme.foreground}
        />
      ) : isSubmitted ? (
        <text style={textStyle({ dim: true, fg: theme.muted })}>{"  "}{loadingText}</text>
      ) : null}

      {/* Input */}
      <box marginTop={1}>
        <PromptInput
          onSubmit={(msg) => onSendMessage(msg.text)}
          onStop={stopHandler}
          status={chatStatus}
          placeholder={placeholder}
          prompt={promptChar}
          promptColor={resolvedPromptColor}
          foregroundColor={theme.foreground}
          submittedText={loadingText}
          focus={focus}
          useKeyboard={useKeyboardProp}
        />
      </box>
    </box>
  )
}

export type GradientName =
  | "cristal" | "teen" | "mind" | "morning" | "vice" | "passion"
  | "fruit" | "instagram" | "atlas" | "retro" | "summer" | "pastel" | "rainbow"

export interface GradientProps {
  /** The text to render with a gradient. Must be a plain string. */
  children: string
  /** Named preset gradient. Mutually exclusive with `colors`. */
  name?: GradientName
  /** Custom array of hex color stops. Mutually exclusive with `name`. */
  colors?: string[]
}

interface RGB { r: number; g: number; b: number }

export const GRADIENTS: Record<GradientName, string[]> = {
  cristal: ["#bdfff3", "#4ac29a"],
  teen: ["#77a1d3", "#79cbca", "#e684ae"],
  mind: ["#473b7b", "#3584a7", "#30d2be"],
  morning: ["#ff5f6d", "#ffc371"],
  vice: ["#5ee7df", "#b490ca"],
  passion: ["#f43b47", "#453a94"],
  fruit: ["#ff4e50", "#f9d423"],
  instagram: ["#833ab4", "#fd1d1d", "#fcb045"],
  atlas: ["#feac5e", "#c779d0", "#4bc0c8"],
  retro: ["#3f51b1", "#5a55ae", "#7b5fac", "#8f6aae", "#a86aa4", "#cc6b8e", "#f18271", "#f3a469", "#f7c978"],
  summer: ["#fdbb2d", "#22c1c3"],
  rainbow: ["#ff0000", "#ffff00", "#00ff00", "#00ffff", "#0000ff", "#ff00ff", "#ff0000"],
  pastel: ["#74ebd5", "#ACB6E5"],
}

export function hexToRgb(hex: string): RGB {
  const normalized = hex.replace("#", "")
  return {
    r: parseInt(normalized.substring(0, 2), 16),
    g: parseInt(normalized.substring(2, 4), 16),
    b: parseInt(normalized.substring(4, 6), 16),
  }
}

export function rgbToHex(rgb: RGB): string {
  const r = rgb.r.toString(16).padStart(2, "0")
  const g = rgb.g.toString(16).padStart(2, "0")
  const b = rgb.b.toString(16).padStart(2, "0")
  return `#${r}${g}${b}`
}

function lerp(a: number, b: number, t: number): number {
  return a + (b - a) * t
}

function interpolateColor(color1: RGB, color2: RGB, t: number): RGB {
  return {
    r: Math.round(lerp(color1.r, color2.r, t)),
    g: Math.round(lerp(color1.g, color2.g, t)),
    b: Math.round(lerp(color1.b, color2.b, t)),
  }
}

export function generateGradient(colors: string[], steps: number): string[] {
  if (colors.length === 0) throw new Error("At least one color is required")
  if (colors.length === 1 || steps <= 1) return Array(steps).fill(colors[0])

  const rgbColors = colors.map(hexToRgb)
  const result: string[] = []
  const segmentLength = (steps - 1) / (rgbColors.length - 1)

  for (let i = 0; i < steps; i++) {
    const segmentIndex = Math.min(Math.floor(i / segmentLength), rgbColors.length - 2)
    const segmentProgress = segmentLength > 0 ? (i - segmentIndex * segmentLength) / segmentLength : 0
    const color = interpolateColor(rgbColors[segmentIndex], rgbColors[segmentIndex + 1], Math.min(segmentProgress, 1))
    result.push(rgbToHex(color))
  }
  return result
}

/** Renders text with a horizontal color gradient interpolated across characters. */
export function Gradient({ children, name, colors }: GradientProps) {
  if (name && colors) throw new Error("The `name` and `colors` props are mutually exclusive")
  if (!name && !colors) throw new Error("Either `name` or `colors` prop must be provided")

  const gradientColors = name ? GRADIENTS[name] : colors!
  const lines = children.split("\n")
  const maxLength = Math.max(...lines.map((l) => l.length))

  if (maxLength === 0) return <text>{children}</text>

  const hexColors = generateGradient(gradientColors, maxLength)

  return (
    <>
      {lines.map((line, lineIndex) => (
        <text key={lineIndex}>
          {line.split("").map((char, charIndex) => (
            <span key={charIndex} style={{ fg: hexColors[charIndex] }}>
              {char}
            </span>
          ))}
        </text>
      ))}
    </>
  )
}

import type { ReactNode } from "react"
import { useTheme } from "./theme"

export type UnderlineStyle = "solid" | "dashed" | "dotted" | "none"

// Attribute bits matching opentui core TextAttributes
const UNDERLINE = 1 << 3
const UNDERLINE_DASHED = 1 << 4
const UNDERLINE_DOTTED = 1 << 6

export interface LinkProps {
  /** Link label content. */
  children: ReactNode
  /** Target URL for the hyperlink. */
  url: string
  /** Underline decoration style. @default "solid" */
  underline?: UnderlineStyle
  /** Override the link color. Defaults to theme.accent. */
  color?: string
}

/** Renders a clickable hyperlink with configurable underline style and color. */
export function Link({ children, url, underline = "solid", color }: LinkProps) {
  const theme = useTheme()
  const resolvedColor = color ?? theme.accent

  let attributes = 0
  if (underline === "solid") {
    attributes = UNDERLINE
  } else if (underline === "dashed") {
    attributes = UNDERLINE | UNDERLINE_DASHED
  } else if (underline === "dotted") {
    attributes = UNDERLINE | UNDERLINE_DOTTED
  }

  return (
    <text>
      <a href={url} style={{ attributes, fg: resolvedColor }}>{children}</a>
    </text>
  )
}

// @ts-nocheck
import { createContext, memo, useContext, useMemo } from "react"
import type { ReactNode } from "react"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"

// ── Role ────────────────────────────────────────────────────────────

export type MessageRole = "user" | "assistant" | "system"

// ── Context ─────────────────────────────────────────────────────────

export interface MessageContextValue {
  role: MessageRole
  isStreaming: boolean
  backgroundColor: string
  textColor: string
}

const MessageContext = createContext<MessageContextValue | null>(null)

export function useMessage(): MessageContextValue {
  const ctx = useContext(MessageContext)
  if (!ctx) throw new Error("useMessage must be used within <Message>")
  return ctx
}

// ── Sub-components ──────────────────────────────────────────────────

export interface MessageContentProps {
  /** Sub-components to render inside the message bubble. */
  children: ReactNode
}

/** Bubble wrapper with background color. Reads bg from Message context. */
export const MessageContent = memo(function MessageContent({ children }: MessageContentProps) {
  const { role, backgroundColor } = useMessage()
  const isUser = role === "user"

  return (
    <box
      flexDirection="column"
      backgroundColor={backgroundColor}
      paddingX={2}
      paddingY={1}
      {...(isUser ? { maxWidth: "85%" } : { width: "85%" })}
    >
      {children}
    </box>
  )
})

export interface MessageTextProps {
  /** Text content to display. */
  children: string
}

/** Renders text with word wrap. */
export const MessageText = memo(function MessageText({ children }: MessageTextProps) {
  const { backgroundColor, textColor } = useMessage()

  return (
    <text wrapMode="word">
      <span style={textStyle({ fg: textColor, bg: backgroundColor })}>{children}</span>
    </text>
  )
})

export interface MessageMarkdownProps {
  /** Markdown string to render. */
  children: string
}

/** Renders markdown content via the OpenTUI markdown intrinsic. */
export const MessageMarkdown = memo(function MessageMarkdown({ children }: MessageMarkdownProps) {
  const { backgroundColor } = useMessage()

  return (
    <box flexDirection="column">
      <markdown content={children} bg={backgroundColor} />
    </box>
  )
})

// ── Message (root component) ────────────────────────────────────────

export interface MessageProps {
  /** Message role — determines alignment and default background. */
  role: MessageRole
  /** Whether this message is currently streaming. */
  isStreaming?: boolean
  /** Override the default background color. */
  backgroundColor?: string
  /** Compose sub-components: MessageContent, MessageText, etc. */
  children: ReactNode
}

/** Chat message bubble with role-based styling. Compose with MessageContent, MessageText, etc. */
export function Message({
  role,
  isStreaming = false,
  backgroundColor,
  children,
}: MessageProps) {
  const theme = useTheme()
  const isUser = role === "user"
  const bg = backgroundColor ?? (isUser ? theme.messageUser : theme.messageAssistant)
  const contextValue = useMemo<MessageContextValue>(
    () => ({ role, isStreaming, backgroundColor: bg, textColor: theme.foreground }),
    [role, isStreaming, bg, theme.foreground],
  )

  return (
    <MessageContext.Provider value={contextValue}>
      <box
        flexDirection="column"
        flexShrink={0}
        width="100%"
        alignItems={isUser ? "flex-end" : "flex-start"}
      >
        {children}
      </box>
    </MessageContext.Provider>
  )
}

// ── Display names for React DevTools ────────────────────────────────

Message.displayName = "Message"
MessageContent.displayName = "MessageContent"
MessageText.displayName = "MessageText"
MessageMarkdown.displayName = "MessageMarkdown"

import type { ReactNode } from "react"
import { FocusScope } from "@gridland/utils"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"
import { useKeyboardContext } from "./provider"

export interface ModalProps {
  /** The content rendered inside the modal border. */
  children: ReactNode
  /** Optional title displayed at the top inside the border. Rendered bold in the borderColor. */
  title?: string
  /** Color of the border and the title text. */
  borderColor?: string
  /**
   * The character set used for drawing the border.
   * Maps to opentui border styles: "single" | "double" | "rounded" | "heavy".
   */
  borderStyle?: "single" | "double" | "rounded" | "heavy"
  /** Callback invoked when the Escape key is pressed. */
  onClose?: () => void
  /** Keyboard handler — pass useKeyboard from @opentui/react */
  useKeyboard?: (handler: (event: any) => void) => void
}

/** Bordered modal overlay with optional title and Escape-to-close. Traps focus automatically. */
export function Modal({
  children,
  title,
  borderColor,
  borderStyle = "rounded",
  onClose,
  useKeyboard: useKeyboardProp,
}: ModalProps) {
  const theme = useTheme()
  const useKeyboard = useKeyboardContext(useKeyboardProp)
  const resolvedBorderColor = borderColor ?? theme.muted

  // Handle Escape key
  useKeyboard?.((event: any) => {
    if (event.name === "escape" && onClose) {
      onClose()
    }
  })

  return (
    <FocusScope trap autoFocus restoreOnUnmount>
      <box flexDirection="column" flexGrow={1}>
        <box
          flexDirection="column"
          flexGrow={1}
          border
          borderStyle={borderStyle}
          borderColor={resolvedBorderColor}
        >
          {title ? (
            <>
              <box paddingX={1} marginBottom={1}>
                <text style={textStyle({ bold: true, fg: theme.primary })}>{title}</text>
              </box>
              {children}
            </>
          ) : (
            children
          )}
        </box>
      </box>
    </FocusScope>
  )
}

// @ts-nocheck — OpenTUI intrinsic elements conflict with React's HTML/SVG types
import { useReducer, useMemo, useRef } from "react"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"
import { useKeyboardContext } from "./provider"

export type MultiSelectItem<V> = {
  /** Unique key for React reconciliation. Falls back to stringified value. */
  key?: string
  /** Display label for this option. */
  label: string
  /**
   * The value returned when this item is selected.
   *
   * Values are compared by reference equality (Set.has). Use primitives
   * (string, number) for reliable behavior. Object references will only
   * match if they are the same instance across renders.
   */
  value: V
  /** Optional group heading this item belongs to. */
  group?: string
  /** Whether this item is non-selectable. */
  disabled?: boolean
}

export interface MultiSelectProps<V> {
  /** Available options. @default [] */
  items?: MultiSelectItem<V>[]
  /** Initially selected values (uncontrolled). @default [] */
  defaultSelected?: V[]
  /** Controlled selected values. */
  selected?: V[]
  /** Called when selection changes. Fires in both controlled and uncontrolled modes. */
  onChange?: (values: V[]) => void
  /** Disable all interaction. */
  disabled?: boolean
  /** Show validation error state. */
  invalid?: boolean
  /** Custom error message when invalid. @default "Please select at least one option" */
  errorMessage?: string
  /** Show required indicator on the title. */
  required?: boolean
  /** Text shown when no items are available. */
  placeholder?: string
  /** Maximum number of selectable items. */
  maxCount?: number
  /** Heading text above the list. @default "Select" */
  title?: string
  /** Status text shown after submission. @default "submitted" */
  submittedStatus?: string
  /** Maximum visible rows before scrolling. @default 12 */
  limit?: number
  /** Allow "a" key to select all. @default true */
  enableSelectAll?: boolean
  /** Allow "x" key to clear selection. @default true */
  enableClear?: boolean
  /** Override the cursor/highlight color. Defaults to theme.primary. */
  highlightColor?: string
  /** Override the checkbox color. Defaults to theme.accent. */
  checkboxColor?: string
  /** Allow submitting with zero selections. @default false */
  allowEmpty?: boolean
  /** Called when the user confirms selection via the Submit row. */
  onSubmit?: (values: V[]) => void
  /** Keyboard handler — pass useKeyboard from @gridland/utils. */
  useKeyboard?: (handler: (event: any) => void) => void
}

type State<V> = {
  cursor: number
  selected: Set<V>
  submitted: boolean
}

type Action<V> =
  | { type: "SET_CURSOR"; cursor: number }
  | { type: "SET_SELECTED"; values: V[] }
  | { type: "SUBMIT" }

function reducer<V>(state: State<V>, action: Action<V>): State<V> {
  switch (action.type) {
    case "SET_CURSOR":
      return { ...state, cursor: action.cursor }
    case "SET_SELECTED":
      return { ...state, selected: new Set(action.values) }
    case "SUBMIT":
      return { ...state, submitted: true }
    default:
      return state
  }
}

const VISIBLE = 12
const BAR = "│"
const CHECKED = "●"
const UNCHECKED = "○"
const CURSOR = "▸"
const SEPARATOR = "─"

type Row<V> =
  | { type: "group"; label: string }
  | { type: "separator" }
  | { type: "item"; item: MultiSelectItem<V>; index: number }

/** Multi-select list with grouping, keyboard navigation, and a submit row. */
export function MultiSelect<V>({
  items = [],
  defaultSelected = [],
  selected: controlledSelected,
  onChange,
  disabled = false,
  invalid = false,
  errorMessage = "Please select at least one option",
  required = false,
  placeholder,
  maxCount,
  title = "Select",
  submittedStatus = "submitted",
  limit,
  enableSelectAll = true,
  enableClear = true,
  highlightColor,
  checkboxColor,
  allowEmpty = false,
  onSubmit,
  useKeyboard: useKeyboardProp,
}: MultiSelectProps<V>) {
  const theme = useTheme()
  const useKeyboard = useKeyboardContext(useKeyboardProp)
  const resolvedHighlight = highlightColor ?? theme.primary
  const resolvedCheckbox = checkboxColor ?? theme.accent

  const isControlled = controlledSelected !== undefined
  const controlledRef = useRef(isControlled)
  if (controlledRef.current !== isControlled) {
    console.warn("MultiSelect: switching between controlled and uncontrolled is not supported.")
  }

  const [state, dispatch] = useReducer(reducer<V>, {
    cursor: 0,
    selected: new Set(isControlled ? controlledSelected : defaultSelected),
    submitted: false,
  })

  const currentSelected = useMemo(
    () => (isControlled ? new Set(controlledSelected) : state.selected),
    [isControlled, controlledSelected, state.selected],
  )

  const { flatRows, selectableItems } = useMemo(() => {
    const rows: Row<V>[] = []
    const selectable: Array<{ item: MultiSelectItem<V>; index: number }> = []
    let index = 0
    const grouped = new Map<string, MultiSelectItem<V>[]>()
    for (const item of items) {
      const group = item.group ?? ""
      const list = grouped.get(group) ?? []
      list.push(item)
      grouped.set(group, list)
    }
    let first = true
    for (const [group, groupItems] of grouped) {
      if (!first) rows.push({ type: "separator" })
      first = false
      if (group) {
        rows.push({ type: "group", label: group })
      }
      for (const item of groupItems) {
        rows.push({ type: "item", item, index })
        selectable.push({ item, index })
        index++
      }
    }
    return { flatRows: rows, selectableItems: selectable }
  }, [items])

  const hasSubmitRow = allowEmpty || currentSelected.size > 0
  const totalPositions = selectableItems.length + (hasSubmitRow ? 1 : 0)

  // Clamp cursor when totalPositions shrinks (e.g., submit row disappears)
  const cursor = totalPositions > 0
    ? Math.min(state.cursor, totalPositions - 1)
    : 0

  // Keep refs in sync so the keyboard handler always reads fresh values
  const cursorRef = useRef(cursor)
  cursorRef.current = cursor

  const currentSelectedRef = useRef(currentSelected)
  currentSelectedRef.current = currentSelected

  const selectableItemsRef = useRef(selectableItems)
  selectableItemsRef.current = selectableItems

  const submittedRef = useRef(state.submitted)
  submittedRef.current = state.submitted

  const isOnSubmit = hasSubmitRow && cursor === selectableItems.length

  const visibleCount = limit ?? VISIBLE
  const cursorRowIndex = flatRows.findIndex((r) => r.type === "item" && r.index === cursor)
  const scrollOffset = Math.max(0, Math.min(cursorRowIndex - Math.floor(visibleCount / 2), flatRows.length - visibleCount))
  const visibleRows = flatRows.slice(scrollOffset, scrollOffset + visibleCount)

  const setSelected = (values: V[]) => {
    if (!isControlled) {
      dispatch({ type: "SET_SELECTED", values })
    }
    onChange?.(values)
  }

  const diamondColor = invalid ? theme.error
    : disabled ? theme.muted
    : theme.accent

  useKeyboard?.((event: any) => {
    if (submittedRef.current || disabled) return

    const sel = currentSelectedRef.current
    const selItems = selectableItemsRef.current
    const hasSubmit = allowEmpty || sel.size > 0
    const total = selItems.length + (hasSubmit ? 1 : 0)

    const move = (direction: 1 | -1) => {
      let next = cursorRef.current
      for (let i = 0; i < total; i++) {
        next += direction
        if (next < 0) next = total - 1
        if (next >= total) next = 0
        // Submit row (last position) is always enabled
        if (next >= selItems.length || !selItems[next]?.item.disabled) break
      }
      cursorRef.current = next
      dispatch({ type: "SET_CURSOR", cursor: next })
    }

    if (event.name === "up" || event.name === "k") {
      move(-1)
      event.preventDefault?.()
    } else if (event.name === "down" || event.name === "j") {
      move(1)
      event.preventDefault?.()
    } else if (event.name === "return" || event.name === "space") {
      const onSubmitRow = hasSubmit && cursorRef.current === selItems.length
      if (onSubmitRow) {
        submittedRef.current = true
        dispatch({ type: "SUBMIT" })
        onSubmit?.(Array.from(sel))
      } else {
        const current = selItems[cursorRef.current]
        if (current && !current.item.disabled) {
          const isDeselecting = sel.has(current.item.value)
          if (!isDeselecting && maxCount !== undefined && sel.size >= maxCount) return
          const next = new Set(sel)
          if (isDeselecting) next.delete(current.item.value)
          else next.add(current.item.value)
          setSelected(Array.from(next))
        }
      }
      event.preventDefault?.()
    } else if (event.name === "a" && enableSelectAll) {
      const enabledValues = items.filter((i) => !i.disabled).map((i) => i.value)
      setSelected(maxCount !== undefined ? enabledValues.slice(0, maxCount) : enabledValues)
      event.preventDefault?.()
    } else if (event.name === "x" && enableClear) {
      setSelected([])
      event.preventDefault?.()
    }
  })

  if (state.submitted) {
    const selectedItems = items.filter((i) => currentSelected.has(i.value))
    return (
      <box flexDirection="column">
        <text>
          <span style={textStyle({ fg: theme.success })}>{"◆ "}</span>
          <span style={textStyle({ bold: true, fg: theme.foreground })}>{title}</span>
        </text>
        {selectedItems.map((item) => (
          <text key={item.key ?? String(item.value)}>
            <span style={textStyle({ fg: theme.success })}>{BAR} </span>
            <span>{"  "}</span>
            <span style={textStyle({ fg: theme.success })}>{CHECKED} </span>
            <span style={textStyle({ fg: theme.foreground })}>{item.label}</span>
          </text>
        ))}
        <text> </text>
        <text>
          <span style={textStyle({ dim: true, fg: theme.muted })}>{selectedItems.length} selected — {submittedStatus}</span>
        </text>
      </box>
    )
  }

  const hasItems = selectableItems.length > 0

  return (
    <box flexDirection="column">
      <text>
        <span style={textStyle({ fg: diamondColor, dim: disabled })}>{"◆ "}</span>
        <span style={textStyle({ bold: true, dim: disabled, fg: theme.foreground })}>{title}</span>
        {required && <span style={textStyle({ fg: theme.error })}>{" *"}</span>}
        {maxCount !== undefined && (
          <span style={textStyle({ dim: true, fg: theme.muted })}>{` (${currentSelected.size}/${maxCount})`}</span>
        )}
      </text>
      {invalid && (
        <text>
          <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
          <span style={textStyle({ fg: theme.error })}>{"  "}{errorMessage}</span>
        </text>
      )}
      {!hasItems && placeholder && (
        <text>
          <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
          <span style={textStyle({ dim: true, fg: theme.muted })}>{"  "}{placeholder}</span>
        </text>
      )}
      {visibleRows.map((row, i) => {
        if (row.type === "separator") {
          const flatIndex = scrollOffset + i
          return (
            <text key={`sep-${flatIndex}`}>
              <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
              <span style={textStyle({ fg: theme.muted })}>{"  "}{SEPARATOR.repeat(20)}</span>
            </text>
          )
        }

        if (row.type === "group") {
          return (
            <text key={`group-${row.label}`}>
              <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
              <span style={textStyle({ bold: true, fg: theme.muted })}>{` ${row.label}`}</span>
            </text>
          )
        }

        const { item, index: itemIndex } = row
        const isHighlighted = !disabled && itemIndex === cursor
        const isSelected = currentSelected.has(item.value)
        const isItemDisabled = disabled || !!item.disabled
        const itemColor = isItemDisabled ? theme.muted
          : isHighlighted ? resolvedHighlight
          : isSelected ? resolvedCheckbox
          : theme.foreground

        return (
          <text key={item.key ?? String(item.value)}>
            <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
            <span style={textStyle({ fg: isHighlighted ? resolvedHighlight : undefined })}>
              {isHighlighted ? CURSOR : " "}{" "}
            </span>
            <span style={textStyle({ fg: isSelected && !isItemDisabled ? resolvedCheckbox : theme.muted, dim: isItemDisabled })}>
              {isSelected ? CHECKED : UNCHECKED}{" "}
            </span>
            <span style={textStyle({ fg: itemColor, dim: isItemDisabled })}>
              {item.label}
            </span>
          </text>
        )
      })}
      {hasSubmitRow && (
        <text>
          <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
          <span style={textStyle({ fg: isOnSubmit ? resolvedHighlight : undefined })}>
            {isOnSubmit ? CURSOR : " "}{" "}
          </span>
          <span style={textStyle({ fg: isOnSubmit ? resolvedHighlight : theme.muted })}>
            {"↳ "}
          </span>
          <span style={textStyle({ fg: isOnSubmit ? resolvedHighlight : theme.foreground })}>
            {"Submit"}
          </span>
        </text>
      )}
    </box>
  )
}

// @ts-nocheck — OpenTUI intrinsic elements conflict with React's HTML/SVG types
import {
  useState,
  useRef,
  useCallback,
  useEffect,
  useMemo,
  createContext,
  useContext,
  type ReactNode,
  type PropsWithChildren,
} from "react"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"
import { useKeyboardContext } from "./provider"
import { useRegistryCommands } from "./command-registry"
export type { PromptInputCommand } from "./command-registry"

/** Chat lifecycle status. Compatible with any AI SDK. */
export type ChatStatus = "ready" | "submitted" | "streaming" | "error"

export interface Suggestion {
  text: string
  desc?: string
  /** Character that triggered this suggestion (e.g. "@", "#"). Used to determine replacement range. */
  trigger?: string
}

/** Message shape passed to onSubmit. */
export interface PromptInputMessage {
  text: string
}

// ============================================================================
// Provider (lifted state)
// ============================================================================

export interface TextInputContext {
  value: string
  setValue: (v: string) => void
  clear: () => void
}

export interface SuggestionsContext {
  suggestions: Suggestion[]
  selectedIndex: number
  setSuggestions: (s: Suggestion[]) => void
  setSelectedIndex: (i: number) => void
  clear: () => void
}

interface PromptInputControllerProps {
  textInput: TextInputContext
  suggestions: SuggestionsContext
}

const PromptInputControllerCtx = createContext<PromptInputControllerProps | null>(null)

/** Access lifted PromptInput state from outside the component. Requires `<PromptInputProvider>`. */
export function usePromptInputController(): PromptInputControllerProps {
  const ctx = useContext(PromptInputControllerCtx)
  if (!ctx) {
    throw new Error("Wrap your component inside <PromptInputProvider> to use usePromptInputController().")
  }
  return ctx
}

const useOptionalController = () => useContext(PromptInputControllerCtx)

export type PromptInputProviderProps = PropsWithChildren<{
  initialInput?: string
}>

/**
 * Optional provider that lifts PromptInput state outside of PromptInput.
 * Without it, PromptInput stays fully self-managed.
 */
export function PromptInputProvider({ initialInput = "", children }: PromptInputProviderProps) {
  const [value, setValueState] = useState(initialInput)
  const clearInput = useCallback(() => setValueState(""), [])

  const [suggestions, setSuggestions] = useState<Suggestion[]>([])
  const [selectedIndex, setSelectedIndex] = useState(0)
  const clearSuggestions = useCallback(() => {
    setSuggestions([])
    setSelectedIndex(0)
  }, [])

  const controller = useMemo<PromptInputControllerProps>(
    () => ({
      textInput: { value, setValue: setValueState, clear: clearInput },
      suggestions: {
        suggestions,
        selectedIndex,
        setSuggestions,
        setSelectedIndex,
        clear: clearSuggestions,
      },
    }),
    [value, clearInput, suggestions, selectedIndex, clearSuggestions],
  )

  return (
    <PromptInputControllerCtx.Provider value={controller}>
      {children}
    </PromptInputControllerCtx.Provider>
  )
}

// ============================================================================
// Component Context (rendering state for subcomponents)
// ============================================================================

export interface PromptInputContextValue {
  value: string
  isFocused: boolean
  disabled: boolean
  status?: ChatStatus
  onStop?: () => void
  statusHintText: string
  placeholder: string
  prompt: string
  promptColor: string
  suggestions: Suggestion[]
  sugIdx: number
  maxSuggestions: number
  errorText: string
  model?: string
  dividerColor?: string
  dividerDashed?: boolean
  theme: ReturnType<typeof useTheme>
  handleInput: (value: string) => void
  handleInputSubmit: (value: string) => void
  handleInputKeyDown: (key: any) => void
}

const PromptInputContext = createContext<PromptInputContextValue | null>(null)

/** Hook for accessing PromptInput state from compound subcomponents. */
export function usePromptInput(): PromptInputContextValue {
  const ctx = useContext(PromptInputContext)
  if (!ctx) {
    throw new Error("usePromptInput must be used within a <PromptInput> component")
  }
  return ctx
}

// ============================================================================
// Props
// ============================================================================

export interface PromptInputProps {
  /** Controlled input value */
  value?: string
  /** Default value for uncontrolled mode */
  defaultValue?: string
  /**
   * Called when user submits a message.
   * Receives `{ text }`. Compatible with Vercel AI SDK's `sendMessage` and
   * easily mapped to any other SDK. If the handler returns a Promise, input
   * is cleared on resolve and preserved on reject so the user can retry.
   */
  onSubmit?: (message: PromptInputMessage) => void | Promise<void>
  /** Callback when input value changes */
  onChange?: (text: string) => void
  /** Placeholder text when input is empty */
  placeholder?: string
  /** Prompt character shown before input */
  prompt?: string
  /** Color of the prompt character */
  promptColor?: string
  /**
   * AI chat status — drives disabled state and status indicator.
   * When provided, takes precedence over `disabled`/`disabledText`.
   */
  status?: ChatStatus
  /** Called when user presses Escape during streaming to stop generation */
  onStop?: () => void
  /** Called when async onSubmit rejects. Lets consumers surface errors (e.g. toast, status update). */
  onError?: (error: unknown) => void
  /** Text shown when status is "submitted" */
  submittedText?: string
  /** Text shown when status is "streaming" */
  streamingText?: string
  /** Text shown when status is "error" */
  errorText?: string
  /** Disable input. Ignored when `status` is provided. */
  disabled?: boolean
  /** Text shown when disabled. Ignored when `status` is provided. */
  disabledText?: string
  /** Slash commands for autocomplete. Commands with `onExecute` are handled internally. */
  commands?: PromptInputCommand[]
  /** Dynamically-provided skills (e.g. from Claude Code). Merged into autocomplete alongside commands. */
  skills?: PromptInputCommand[]
  /** File paths for @ mention autocomplete */
  files?: string[]
  /** Custom suggestion provider — overrides commands/files */
  getSuggestions?: (value: string) => Suggestion[]
  /** Max visible suggestions */
  maxSuggestions?: number
  /** Enable command history with up/down arrows */
  enableHistory?: boolean
  /** Model name displayed below the input */
  model?: string
  /** Whether the input is focused and accepting keystrokes */
  focus?: boolean
  /** Show horizontal dividers above and below the input */
  showDividers?: boolean
  /** Auto-focus the input on mount (ensures canvas has keyboard focus in the browser) */
  autoFocus?: boolean
  /** Override divider line color (e.g. for focus indicators) */
  dividerColor?: string
  /** Use dashed divider lines (╌) instead of solid (─) */
  dividerDashed?: boolean
  /** Keyboard hook from @gridland/utils */
  useKeyboard?: (handler: (event: any) => void) => void
  /** Compound mode: provide subcomponents as children */
  children?: ReactNode
}

// ============================================================================
// Helpers
// ============================================================================

function computeDefaultSuggestions(
  input: string,
  commands: PromptInputCommand[],
  files: string[],
): Suggestion[] {
  if (input.startsWith("/") && commands.length > 0) {
    return commands
      .filter((c) => !c.hidden && c.cmd.startsWith(input))
      .map((c) => ({ text: c.cmd, desc: c.desc }))
  }
  if (input.includes("@") && files.length > 0) {
    const query = input.split("@").pop() ?? ""
    return files
      .filter((f) => f.toLowerCase().includes(query.toLowerCase()))
      .map((f) => ({ text: "@" + f, trigger: "@" }))
  }
  return []
}

function resolveStatusHintText(
  status: ChatStatus | undefined,
  submittedText: string,
  streamingText: string,
  errorText: string,
  disabledText: string,
): string {
  if (status === "submitted") return submittedText
  if (status === "streaming") return streamingText
  if (status === "error") return errorText
  return disabledText
}

// ============================================================================
// Subcomponents
// ============================================================================

/** Horizontal divider line that extends into parent border gutters. */
function PromptInputDivider() {
  const { dividerColor, dividerDashed, theme } = usePromptInput()
  const color = dividerColor ?? theme.muted
  const char = dividerDashed ? "╌" : "─"
  return (
    <text wrapMode="none" marginLeft={-1} marginRight={-1}>
      <span style={textStyle({ dim: !dividerColor, fg: color })}>{char.repeat(500)}</span>
    </text>
  )
}

/** Autocomplete suggestion list. */
function PromptInputSuggestions() {
  const { suggestions, sugIdx, maxSuggestions, theme } = usePromptInput()
  const visible = suggestions.slice(0, maxSuggestions)
  if (visible.length === 0) return null
  return (
    <box flexDirection="column" marginLeft={2}>
      {visible.map((sug, i) => {
        const active = i === sugIdx
        return (
          <text key={sug.text}>
            <span style={textStyle({ fg: active ? theme.primary : theme.muted })}>
              {active ? "▸ " : "  "}
            </span>
            <span style={textStyle({ fg: active ? theme.primary : theme.muted, bold: active })}>
              {sug.text}
            </span>
            {sug.desc && (
              <span style={textStyle({ dim: true, fg: theme.placeholder })}>{" " + sug.desc}</span>
            )}
          </text>
        )
      })}
    </box>
  )
}

/** Prompt char + input element when focused, static text otherwise. */
function PromptInputTextarea() {
  const { value, isFocused, disabled, statusHintText, placeholder, prompt, promptColor, theme, handleInput, handleInputSubmit, handleInputKeyDown } = usePromptInput()
  return (
    <box flexDirection="row">
      <text><span style={textStyle({ fg: promptColor })}>{prompt}</span></text>
      {isFocused ? (
        <input
          value={value}
          placeholder={placeholder}
          focused
          onInput={handleInput}
          onSubmit={handleInputSubmit}
          onKeyDown={handleInputKeyDown}
          cursorColor={theme.muted}
          cursorStyle={{ style: "line", blinking: !value }}
          placeholderColor={theme.placeholder}
          textColor={theme.foreground}
        />
      ) : disabled && value.length === 0 ? (
        <text><span style={textStyle({ dim: true, fg: theme.placeholder })}>{statusHintText}</span></text>
      ) : (
        <text><span style={textStyle({ fg: value ? theme.foreground : theme.placeholder, dim: !value })}>{value || placeholder}</span></text>
      )}
    </box>
  )
}

/**
 * Status indicator: ⏎ ready, ◐ submitted, ■ streaming, ✕ error.
 * When `status` and `onStop` are provided via context, the streaming icon
 * doubles as a stop button (Escape triggers onStop).
 */
function PromptInputSubmit(props: { status?: ChatStatus; onStop?: () => void }) {
  const ctx = usePromptInput()
  const status = props.status ?? ctx.status
  const onStop = props.onStop ?? ctx.onStop
  const { disabled, theme } = ctx

  const isGenerating = status === "submitted" || status === "streaming"

  const icon =
    status === "submitted" ? "◐"
    : status === "streaming" ? (onStop ? "■" : "◐")
    : status === "error" ? "✕"
    : "⏎"

  const color =
    status === "error" ? theme.error
    : isGenerating ? theme.muted
    : disabled ? theme.muted
    : theme.primary

  return (
    <text>
      <span style={textStyle({ fg: color })}>{" " + icon}</span>
    </text>
  )
}

/** Error/hint text below input. */
function PromptInputStatusText() {
  const { status, errorText, theme } = usePromptInput()
  if (status !== "error") return null
  return (
    <text>
      <span style={textStyle({ fg: theme.error })}>{errorText}</span>
    </text>
  )
}

/** Model label shown below the input. */
function PromptInputModel() {
  const { model, theme } = usePromptInput()
  if (!model) return null
  return (
    <text><span style={textStyle({ dim: true, fg: theme.muted })}>{"model: " + model}</span></text>
  )
}

// ============================================================================
// Root component
// ============================================================================

/** Text input with slash-command autocomplete, history, and AI chat status integration. */
export function PromptInput({
  value: controlledValue,
  defaultValue = "",
  onSubmit,
  onChange,
  placeholder = "Type a message...",
  prompt = "❯ ",
  promptColor,
  status,
  onStop,
  onError,
  submittedText = "Thinking...",
  streamingText: streamingLabel = "Generating...",
  errorText = "An error occurred. Try again.",
  disabled: disabledProp = false,
  disabledText = "Generating...",
  commands = [],
  skills = [],
  files = [],
  getSuggestions: customGetSuggestions,
  maxSuggestions = 5,
  enableHistory = true,
  model,
  focus = false,
  showDividers = true,
  autoFocus = false,
  dividerColor,
  dividerDashed,
  useKeyboard: useKeyboardProp,
  children,
}: PromptInputProps) {
  const theme = useTheme()
  const useKeyboard = useKeyboardContext(useKeyboardProp)

  const registryCommands = useRegistryCommands()
  const allCommands = useMemo(() => {
    const base = [...commands, ...skills]
    if (registryCommands.length === 0) return base
    const propCmds = new Set(base.map(c => c.cmd))
    const deduped = registryCommands.filter(c => !propCmds.has(c.cmd))
    return [...base, ...deduped]
  }, [commands, skills, registryCommands])

  // Auto-focus: ensure the canvas has DOM focus so keyboard events reach useKeyboard
  useEffect(() => {
    if (!autoFocus) return
    if (typeof document === "undefined") return
    const canvas = document.querySelector("canvas")
    if (canvas && document.activeElement !== canvas) {
      canvas.focus()
    }
  }, [autoFocus])
  const resolvedPromptColor = promptColor ?? theme.muted

  // Status-driven state
  const disabled = status ? status === "submitted" || status === "streaming" : disabledProp
  const isFocused = focus && !disabled
  const statusHintText = resolveStatusHintText(status, submittedText, streamingLabel, errorText, disabledText)

  // ── Dual-mode state: provider-managed or self-managed ──────────────────
  const controller = useOptionalController()
  const usingProvider = !!controller

  const isControlled = controlledValue !== undefined
  const controlledRef = useRef(isControlled)
  if (controlledRef.current !== isControlled) {
    console.warn("PromptInput: switching between controlled and uncontrolled is not supported.")
  }

  // Local state (used when no provider and not controlled)
  const [localValue, setLocalValue] = useState(defaultValue)
  const [localSuggestions, setLocalSuggestions] = useState<Suggestion[]>([])
  const [localSugIdx, setLocalSugIdx] = useState(0)
  const [history, setHistory] = useState<string[]>([])
  const [histIdx, setHistIdx] = useState(-1)

  // Resolve value from: controlled prop > provider > local
  const value = isControlled
    ? controlledValue
    : usingProvider
      ? controller.textInput.value
      : localValue

  const suggestions = usingProvider ? controller.suggestions.suggestions : localSuggestions
  const sugIdx = usingProvider ? controller.suggestions.selectedIndex : localSugIdx

  // ── State updaters (unified across modes) ──────────────────────────────

  const valueRef = useRef(defaultValue)
  if (isControlled) valueRef.current = controlledValue
  else if (usingProvider) valueRef.current = controller.textInput.value
  else valueRef.current = localValue

  const suggestionsRef = useRef<Suggestion[]>([])
  suggestionsRef.current = suggestions
  const sugIdxRef = useRef(0)
  sugIdxRef.current = sugIdx
  const historyRef = useRef<string[]>([])
  historyRef.current = history
  const histIdxRef = useRef(-1)
  histIdxRef.current = histIdx

  const setSug = useCallback((next: Suggestion[]) => {
    suggestionsRef.current = next
    if (usingProvider) {
      controller.suggestions.setSuggestions(next)
    } else {
      setLocalSuggestions(next)
    }
  }, [usingProvider, controller])

  const setSugI = useCallback((next: number) => {
    sugIdxRef.current = next
    if (usingProvider) {
      controller.suggestions.setSelectedIndex(next)
    } else {
      setLocalSugIdx(next)
    }
  }, [usingProvider, controller])

  const setHist = useCallback((next: string[]) => {
    historyRef.current = next
    setHistory(next)
  }, [])

  const setHistI = useCallback((next: number) => {
    histIdxRef.current = next
    setHistIdx(next)
  }, [])

  const computeSuggestions = useCallback((input: string): Suggestion[] => {
    if (customGetSuggestions) return customGetSuggestions(input)
    return computeDefaultSuggestions(input, allCommands, files)
  }, [customGetSuggestions, allCommands, files])

  const updateValue = useCallback((next: string) => {
    valueRef.current = next
    if (isControlled) {
      // controlled: only fire onChange, parent owns state
    } else if (usingProvider) {
      controller.textInput.setValue(next)
    } else {
      setLocalValue(next)
    }
    onChange?.(next)
    const sug = computeSuggestions(next)
    setSug(sug)
    setSugI(0)
  }, [isControlled, usingProvider, controller, onChange, computeSuggestions, setSug, setSugI])

  // ── Submit handler (auto-clears on success, preserves on error) ────────

  const clearInput = useCallback(() => {
    valueRef.current = ""
    if (usingProvider) {
      controller.textInput.clear()
      controller.suggestions.clear()
    } else if (!isControlled) {
      setLocalValue("")
    }
    setSug([])
    setSugI(0)
    onChange?.("")
  }, [usingProvider, controller, isControlled, onChange, setSug, setSugI])

  const handleSubmit = useCallback((text: string) => {
    const matched = allCommands.find((c) => c.cmd === text)
    if (matched?.onExecute) {
      matched.onExecute()
      clearInput()
      return
    }

    if (!onSubmit) { clearInput(); return }

    const result = onSubmit({ text })

    // Handle async onSubmit: clear on resolve, preserve on reject
    if (result instanceof Promise) {
      result.then(
        () => clearInput(),
        (err: unknown) => { onError?.(err) },
      )
    } else {
      // Sync onSubmit completed without throwing — clear
      clearInput()
    }
  }, [onSubmit, onError, clearInput, allCommands])

  // ── Shared keyboard action handler (used by both <input> and useKeyboard) ──

  const handleKeyAction = useCallback((keyName: string): boolean => {
    if (keyName === "return") {
      if (suggestionsRef.current.length > 0) {
        const sel = suggestionsRef.current[sugIdxRef.current]
        if (sel) {
          if (valueRef.current.startsWith("/")) {
            if (enableHistory) {
              setHist([sel.text, ...historyRef.current])
            }
            setHistI(-1)
            handleSubmit(sel.text)
          } else {
            const triggerIdx = sel.trigger ? valueRef.current.lastIndexOf(sel.trigger) : -1
            const base = triggerIdx >= 0 ? valueRef.current.slice(0, triggerIdx) : ""
            updateValue(base + sel.text + " ")
            setSug([])
          }
        }
      } else {
        const trimmed = valueRef.current.trim()
        if (!trimmed) return true
        if (enableHistory) {
          setHist([trimmed, ...historyRef.current])
        }
        setHistI(-1)
        handleSubmit(trimmed)
      }
      return true
    }

    if (keyName === "tab" && suggestionsRef.current.length > 0) {
      setSugI((sugIdxRef.current + 1) % suggestionsRef.current.length)
      return true
    }

    if (keyName === "up") {
      if (suggestionsRef.current.length > 0) {
        setSugI(Math.max(0, sugIdxRef.current - 1))
      } else if (enableHistory && historyRef.current.length > 0) {
        const idx = Math.min(historyRef.current.length - 1, histIdxRef.current + 1)
        setHistI(idx)
        updateValue(historyRef.current[idx]!)
      }
      return true
    }

    if (keyName === "down") {
      if (suggestionsRef.current.length > 0) {
        setSugI(Math.min(suggestionsRef.current.length - 1, sugIdxRef.current + 1))
      } else if (enableHistory && histIdxRef.current > 0) {
        const nextIdx = histIdxRef.current - 1
        setHistI(nextIdx)
        updateValue(historyRef.current[nextIdx]!)
      } else if (enableHistory && histIdxRef.current === 0) {
        setHistI(-1)
        updateValue("")
      }
      return true
    }

    if (keyName === "escape") {
      if (suggestionsRef.current.length > 0) {
        setSug([])
        return true
      }
      return false
    }

    return false
  }, [enableHistory, handleSubmit, updateValue, setSug, setSugI, setHist, setHistI])

  // ── Input handlers (passed to <input> intrinsic via context) ───────────

  const handleInputSubmit = (text: string) => {
    const trimmed = text.trim()
    if (!trimmed) return
    if (enableHistory) {
      setHist([trimmed, ...historyRef.current])
    }
    setHistI(-1)
    handleSubmit(trimmed)
  }

  const handleInputKeyDown = (key: any) => {
    if (handleKeyAction(key.name)) {
      key.preventDefault()
    }
  }

  // ── Keyboard handler ───────────────────────────────────────────────────
  // When focused, <input> handles text input; useKeyboard only handles Escape→onStop.
  // When not focused (no <input> rendered), useKeyboard provides full keyboard fallback
  // for character input, suggestions, and history (used in tests and unfocused state).

  useKeyboard?.((event: any) => {
    // Escape during submitted/streaming calls onStop (always active)
    if (event.name === "escape" && (status === "streaming" || status === "submitted") && onStop) {
      onStop()
      return
    }

    // When <input> is rendered, it handles everything else
    if (isFocused) return

    if (disabled) return

    if (handleKeyAction(event.name)) return

    if (event.name === "backspace" || event.name === "delete") {
      updateValue(valueRef.current.slice(0, -1))
      return
    }

    if (event.ctrl || event.meta) return

    if (event.name === "space") {
      updateValue(valueRef.current + " ")
      return
    }

    if (event.name && event.name.length === 1) {
      updateValue(valueRef.current + event.name)
    }
  })

  // ── Build context for subcomponents ────────────────────────────────────

  const visibleSuggestions = suggestions.slice(0, maxSuggestions)

  const ctxValue: PromptInputContextValue = {
    value,
    isFocused,
    disabled,
    status,
    onStop,
    statusHintText,
    placeholder,
    prompt,
    promptColor: resolvedPromptColor,
    suggestions: visibleSuggestions,
    sugIdx,
    maxSuggestions,
    errorText,
    model,
    dividerColor,
    dividerDashed,
    theme,
    handleInput: updateValue,
    handleInputSubmit,
    handleInputKeyDown,
  }

  // ── Render ─────────────────────────────────────────────────────────────

  if (children) {
    return (
      <PromptInputContext.Provider value={ctxValue}>
        <box flexDirection="column" flexShrink={0}>
          {children}
        </box>
      </PromptInputContext.Provider>
    )
  }

  return (
    <PromptInputContext.Provider value={ctxValue}>
      <box flexDirection="column" flexShrink={0}>
        {showDividers && <PromptInputDivider />}
        <box flexDirection="column" paddingX={1}>
          <PromptInputSuggestions />
          <PromptInputTextarea />
          <PromptInputStatusText />
        </box>
        {showDividers && <PromptInputDivider />}
        <box paddingX={1}>
          <PromptInputModel />
        </box>
      </box>
    </PromptInputContext.Provider>
  )
}

// ── Attach subcomponents ─────────────────────────────────────────────────

PromptInput.Textarea = PromptInputTextarea
PromptInput.Suggestions = PromptInputSuggestions
PromptInput.Submit = PromptInputSubmit
PromptInput.Divider = PromptInputDivider
PromptInput.StatusText = PromptInputStatusText
PromptInput.Model = PromptInputModel

// @ts-nocheck — OpenTUI intrinsic elements conflict with React's HTML/SVG types
import { useReducer, useMemo, useRef } from "react"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"
import { useKeyboardContext } from "./provider"

export type SelectInputItem<V> = {
  /** Unique key for React reconciliation. Falls back to stringified value. */
  key?: string
  /** Display label for this option. */
  label: string
  /** The value returned when this item is selected. Compared by `===`; use primitives. */
  value: V
  /** Optional group heading this item belongs to. */
  group?: string
  /** Whether this item is non-selectable. */
  disabled?: boolean
}

export interface SelectInputProps<V> {
  /** Available options. @default [] */
  items?: SelectInputItem<V>[]
  /** Initially selected value (uncontrolled). */
  defaultValue?: V
  /** Controlled selected value. */
  value?: V
  /** Called when the highlighted item changes (controlled mode). */
  onChange?: (value: V) => void
  /** Disable all interaction. */
  disabled?: boolean
  /** Show validation error state. */
  invalid?: boolean
  /** Custom error message when invalid. @default "Please select an option" */
  errorMessage?: string
  /** Show required indicator on the title. */
  required?: boolean
  /** Text shown when no items are available. */
  placeholder?: string
  /** Heading text above the list. @default "Select" */
  title?: string
  /** Status text shown after submission. @default "submitted" */
  submittedStatus?: string
  /** Maximum visible rows before scrolling. @default 12 */
  limit?: number
  /** Override the cursor/highlight color. Defaults to theme.primary. */
  highlightColor?: string
  /** Override the radio indicator color. Defaults to theme.muted. */
  radioColor?: string
  /** Called when the user confirms selection via Enter. */
  onSubmit?: (value: V) => void
  /** Keyboard handler — pass useKeyboard from @gridland/utils. */
  useKeyboard?: (handler: (event: any) => void) => void
}

type State = {
  cursor: number
  submitted: boolean
}

type Action =
  | { type: "SET_CURSOR"; cursor: number }
  | { type: "SUBMIT" }

function reducer(state: State, action: Action): State {
  switch (action.type) {
    case "SET_CURSOR":
      return { ...state, cursor: action.cursor }
    case "SUBMIT":
      return { ...state, submitted: true }
    default:
      return state
  }
}

const VISIBLE = 12
const BAR = "│"
const RADIO = "○"
const CURSOR = "▸"
const SEPARATOR = "─"

type Row<V> =
  | { type: "group"; label: string }
  | { type: "separator" }
  | { type: "item"; item: SelectInputItem<V>; index: number }

/** Single-select list with grouping and keyboard navigation. */
export function SelectInput<V>({
  items = [],
  defaultValue,
  value: controlledValue,
  onChange,
  disabled = false,
  invalid = false,
  errorMessage = "Please select an option",
  required = false,
  placeholder,
  title = "Select",
  submittedStatus = "submitted",
  limit,
  highlightColor,
  radioColor,
  onSubmit,
  useKeyboard: useKeyboardProp,
}: SelectInputProps<V>) {
  const theme = useTheme()
  const useKeyboard = useKeyboardContext(useKeyboardProp)
  const resolvedHighlight = highlightColor ?? theme.primary
  const resolvedRadio = radioColor ?? theme.muted

  const isControlled = controlledValue !== undefined
  const controlledRef = useRef(isControlled)
  if (controlledRef.current !== isControlled) {
    console.warn("SelectInput: switching between controlled and uncontrolled is not supported.")
  }

  const initialIndex = items.findIndex((i) => i.value === (isControlled ? controlledValue : defaultValue))

  const [state, dispatch] = useReducer(reducer, {
    cursor: Math.max(0, initialIndex),
    submitted: false,
  })

  const { flatRows, selectableItems } = useMemo(() => {
    const rows: Row<V>[] = []
    const selectable: Array<{ item: SelectInputItem<V>; index: number }> = []
    let index = 0
    const grouped = new Map<string, SelectInputItem<V>[]>()
    for (const item of items) {
      const group = item.group ?? ""
      const list = grouped.get(group) ?? []
      list.push(item)
      grouped.set(group, list)
    }
    let first = true
    for (const [group, groupItems] of grouped) {
      if (!first) rows.push({ type: "separator" })
      first = false
      if (group) {
        rows.push({ type: "group", label: group })
      }
      for (const item of groupItems) {
        rows.push({ type: "item", item, index })
        selectable.push({ item, index })
        index++
      }
    }
    return { flatRows: rows, selectableItems: selectable }
  }, [items])

  const cursor = selectableItems.length > 0
    ? Math.min(state.cursor, selectableItems.length - 1)
    : 0

  const cursorRef = useRef(cursor)
  cursorRef.current = cursor

  const submittedRef = useRef(state.submitted)
  submittedRef.current = state.submitted

  const selectableItemsRef = useRef(selectableItems)
  selectableItemsRef.current = selectableItems

  const visibleCount = limit ?? VISIBLE
  const cursorRowIndex = flatRows.findIndex((r) => r.type === "item" && r.index === cursor)
  const scrollOffset = Math.max(0, Math.min(cursorRowIndex - Math.floor(visibleCount / 2), Math.max(0, flatRows.length - visibleCount)))
  const visibleRows = flatRows.slice(scrollOffset, scrollOffset + visibleCount)

  const diamondColor = invalid ? theme.error
    : disabled ? theme.muted
    : theme.accent

  useKeyboard?.((event: any) => {
    if (submittedRef.current || disabled) return
    const items = selectableItemsRef.current
    const total = items.length

    const findNextEnabled = (from: number, direction: 1 | -1): number => {
      let next = from
      for (let i = 0; i < total; i++) {
        next += direction
        if (next < 0) next = total - 1
        if (next >= total) next = 0
        if (!items[next]?.item.disabled) return next
      }
      return from // all disabled — stay put
    }

    if (event.name === "up" || event.name === "k") {
      const next = findNextEnabled(cursorRef.current, -1)
      cursorRef.current = next
      dispatch({ type: "SET_CURSOR", cursor: next })
      const nextItem = items[next]
      if (nextItem) onChange?.(nextItem.item.value)
      event.preventDefault?.()
    } else if (event.name === "down" || event.name === "j") {
      const next = findNextEnabled(cursorRef.current, 1)
      cursorRef.current = next
      dispatch({ type: "SET_CURSOR", cursor: next })
      const nextItem = items[next]
      if (nextItem) onChange?.(nextItem.item.value)
      event.preventDefault?.()
    } else if (event.name === "return") {
      const current = items[cursorRef.current]
      if (current && !current.item.disabled) {
        dispatch({ type: "SUBMIT" })
        onSubmit?.(isControlled ? controlledValue : current.item.value)
      }
      event.preventDefault?.()
    }
  })

  if (state.submitted) {
    const selectedItem = isControlled
      ? items.find((i) => i.value === controlledValue)
      : selectableItems[cursor]?.item
    return (
      <box flexDirection="column">
        <text>
          <span style={textStyle({ fg: theme.success })}>{"◆ "}</span>
          <span style={textStyle({ bold: true, fg: theme.foreground })}>{title}</span>
        </text>
        {selectedItem && (
          <text>
            <span style={textStyle({ fg: theme.success })}>{BAR} </span>
            <span>{"  "}</span>
            <span style={textStyle({ fg: theme.success })}>{"● "}</span>
            <span style={textStyle({ fg: theme.foreground })}>{selectedItem.label}</span>
          </text>
        )}
        <text> </text>
        <text>
          <span style={textStyle({ dim: true, fg: theme.muted })}>{submittedStatus}</span>
        </text>
      </box>
    )
  }

  const hasItems = selectableItems.length > 0

  return (
    <box flexDirection="column">
      <text>
        <span style={textStyle({ fg: diamondColor, dim: disabled })}>{"◆ "}</span>
        <span style={textStyle({ bold: true, dim: disabled, fg: theme.foreground })}>{title}</span>
        {required && <span style={textStyle({ fg: theme.error })}>{" *"}</span>}
      </text>
      {invalid && (
        <text>
          <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
          <span style={textStyle({ fg: theme.error })}>{"  "}{errorMessage}</span>
        </text>
      )}
      {!hasItems && placeholder && (
        <text>
          <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
          <span style={textStyle({ dim: true, fg: theme.muted })}>{"  "}{placeholder}</span>
        </text>
      )}
      {visibleRows.map((row, i) => {
        if (row.type === "separator") {
          return (
            <text key={`sep-${scrollOffset + i}`}>
              <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
              <span style={textStyle({ fg: theme.muted })}>{"  "}{SEPARATOR.repeat(20)}</span>
            </text>
          )
        }

        if (row.type === "group") {
          return (
            <text key={`group-${row.label}`}>
              <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
              <span style={textStyle({ bold: true, fg: theme.muted })}>{` ${row.label}`}</span>
            </text>
          )
        }

        const { item, index: itemIndex } = row
        const isHighlighted = !disabled && itemIndex === cursor
        const isItemDisabled = disabled || !!item.disabled
        const itemColor = isItemDisabled ? theme.muted
          : isHighlighted ? resolvedHighlight
          : theme.foreground

        return (
          <text key={item.key ?? String(item.value)}>
            <span style={textStyle({ fg: theme.muted })}>{BAR} </span>
            <span style={textStyle({ fg: isHighlighted ? resolvedHighlight : undefined })}>
              {isHighlighted ? CURSOR : " "}{" "}
            </span>
            <span style={textStyle({ fg: resolvedRadio, dim: isItemDisabled })}>
              {RADIO}{" "}
            </span>
            <span style={textStyle({ fg: itemColor, dim: isItemDisabled })}>
              {item.label}
            </span>
          </text>
        )
      })}
    </box>
  )
}

// @ts-nocheck
import { useEffect, useState } from "react"
import { useTheme } from "./theme"

const VARIANTS = {
  dots: { frames: ["⠋", "⠙", "⠹", "⠸", "⠼", "⠴", "⠦", "⠧", "⠇", "⠏"], interval: 80 },
  pulse: { frames: ["·", "∙", "●", "∙", "·", "·", "·"], interval: 180 },
  meter: { frames: ["▱▱▱", "▰▱▱", "▰▰▱", "▰▰▰", "▰▰▱", "▰▱▱", "▱▱▱"], interval: 143 },
  bloom: { frames: ["·", "✦", "✧", "✹", "✺", "❋", "✸", "✵", "✸", "❋", "✺", "✹", "✧", "✦", "·", "·"], interval: 100 },
  ellipsis: { frames: ["   ", ".  ", ".. ", "..."], interval: 333 },
} as const

export type SpinnerVariant = keyof typeof VARIANTS
export type SpinnerStatus = "spinning" | "success" | "error" | "warning" | "info"

export const VARIANT_NAMES = Object.keys(VARIANTS) as SpinnerVariant[]

const STATUS_SYMBOLS: Record<Exclude<SpinnerStatus, "spinning">, string> = {
  success: "✔",
  error: "✖",
  warning: "⚠",
  info: "ℹ",
}

export interface SpinnerProps {
  /** Animation variant. @default "dots" */
  variant?: SpinnerVariant
  /** Label text shown to the right of the spinner. */
  text?: string
  /** Override the spinner color. Defaults to theme.accent. */
  color?: string
  /** Current status. Non-"spinning" values show a static icon instead of animating. @default "spinning" */
  status?: SpinnerStatus
}

/** Animated spinner with multiple variants and terminal status icons. */
export function Spinner({ variant = "dots", text, color, status = "spinning" }: SpinnerProps) {
  const theme = useTheme()
  const { frames, interval } = VARIANTS[variant]
  const [frame, setFrame] = useState(0)

  useEffect(() => {
    if (status !== "spinning") return
    setFrame(0)
    const timer = setInterval(() => {
      setFrame((prev) => (prev + 1) % frames.length)
    }, interval)
    return () => clearInterval(timer)
  }, [variant, status])

  if (status !== "spinning") {
    const symbol = STATUS_SYMBOLS[status]
    const statusColor =
      status === "success" ? theme.success :
      status === "error" ? theme.error :
      status === "warning" ? theme.warning :
      theme.accent
    return (
      <text>
        <span style={{ fg: statusColor }}>{symbol}</span>
        {text ? <span style={{ fg: theme.foreground }}> {text}</span> : null}
      </text>
    )
  }

  const resolvedColor = color ?? theme.accent
  return (
    <text>
      <span style={{ fg: resolvedColor }}>{frames[frame]}</span>
      {text ? <span style={{ fg: theme.foreground }}> {text}</span> : null}
    </text>
  )
}

import type { ReactNode } from "react"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"

export interface StatusBarItem {
  /** The key or key combination text (e.g., "Tab", "←→", "q"). */
  key: string
  /** Description of what the key does (e.g., "switch focus", "navigate"). */
  label: string
}

export interface StatusBarProps {
  /** Array of keybinding hints to display. */
  items: StatusBarItem[]
  /**
   * Optional content rendered to the left of the keybinding hints.
   * When provided, a dim │ separator appears between it and the hints.
   *
   * **Note:** Since this renders inside a `<text>`, it must be inline content
   * (`<span>` or string). Block-level elements will cause rendering errors.
   */
  extra?: ReactNode
}

/** Horizontal bar displaying keybinding hints with optional extra content. */
export function StatusBar({ items, extra }: StatusBarProps) {
  const theme = useTheme()
  const parts: any[] = []

  if (extra !== undefined) {
    parts.push(
      <span key="extra">{extra}</span>,
    )
    parts.push(
      <span key="pipe" style={textStyle({ dim: true, fg: theme.placeholder })}>{"  \u2502  "}</span>,
    )
  }

  items.forEach((item, i) => {
    if (i > 0) {
      parts.push(<span key={`gap-${i}`}>{" "}</span>)
    }
    parts.push(
      <span key={`key-${i}`} style={textStyle({ bold: true, fg: theme.background, bg: theme.muted })}>
        {` ${item.key} `}
      </span>,
    )
    parts.push(
      <span key={`label-${i}`} style={textStyle({ dim: true, fg: theme.placeholder })}>
        {` ${item.label}`}
      </span>,
    )
  })

  if (parts.length === 0) {
    return null
  }

  return <text>{parts}</text>
}

import { createContext, useContext, useState, Children, isValidElement } from "react"
import type { ReactNode } from "react"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"
import { useKeyboardContext } from "./provider"

// ── Context ──────────────────────────────────────────────────────────────

interface TabsContextValue {
  value: string
  onValueChange: (value: string) => void
}

const TabsContext = createContext<TabsContextValue | null>(null)

function useTabsContext() {
  const ctx = useContext(TabsContext)
  if (!ctx) throw new Error("Tabs compound components must be used within <Tabs>")
  return ctx
}

// ── Tabs (root) ──────────────────────────────────────────────────────────

export interface TabsProps {
  /** The controlled active tab value. */
  value?: string
  /** The default active tab value (uncontrolled). */
  defaultValue?: string
  /** Called when the active tab changes. */
  onValueChange?: (value: string) => void
  children: ReactNode
}

/** Root compound component for tabbed navigation. Manages active tab state. */
export function Tabs({
  value: controlledValue,
  defaultValue = "",
  onValueChange,
  children,
}: TabsProps) {
  const [internalValue, setInternalValue] = useState(defaultValue)
  const value = controlledValue ?? internalValue
  const handleChange = onValueChange ?? setInternalValue

  return (
    <TabsContext.Provider value={{ value, onValueChange: handleChange }}>
      <box flexDirection="column">{children}</box>
    </TabsContext.Provider>
  )
}

// ── TabsList ─────────────────────────────────────────────────────────────

export interface TabsListProps {
  /** Optional label shown before the tab triggers. */
  label?: string
  /** Whether the tab bar appears focused. */
  focused?: boolean
  /** The foreground color applied to the active trigger. */
  activeColor?: string
  /** Whether to show the horizontal separator below the triggers. */
  separator?: boolean
  /** Keyboard handler — pass useKeyboard from @gridland/utils */
  useKeyboard?: (handler: (event: any) => void) => void
  children: ReactNode
}

/** Renders the tab trigger row with keyboard navigation and optional separator. */
export function TabsList({
  label,
  focused = true,
  activeColor,
  separator = true,
  useKeyboard: useKeyboardProp,
  children,
}: TabsListProps) {
  const theme = useTheme()
  const { value, onValueChange } = useTabsContext()
  const useKeyboard = useKeyboardContext(useKeyboardProp)
  const color = activeColor ?? theme.accent

  // Extract trigger values and labels from children
  const triggers: { value: string; label: ReactNode }[] = []
  Children.forEach(children, (child) => {
    if (isValidElement(child) && "value" in child.props) {
      triggers.push({ value: child.props.value as string, label: child.props.children })
    }
  })

  // Keyboard navigation: left/right arrows switch tabs
  useKeyboard?.((event: any) => {
    if (triggers.length === 0) return
    const currentIndex = triggers.findIndex((t) => t.value === value)
    if (event.name === "left" || event.name === "h") {
      const next = currentIndex <= 0 ? triggers.length - 1 : currentIndex - 1
      onValueChange(triggers[next].value)
      event.preventDefault?.()
    } else if (event.name === "right" || event.name === "l") {
      const next = currentIndex >= triggers.length - 1 ? 0 : currentIndex + 1
      onValueChange(triggers[next].value)
      event.preventDefault?.()
    }
  })

  const parts: any[] = []

  if (label !== undefined) {
    parts.push(
      <span
        key="label"
        style={focused ? textStyle({ bold: true, fg: theme.foreground }) : textStyle({ dim: true, fg: theme.muted })}
      >
        {label}{" "}
      </span>,
    )
  }

  triggers.forEach((trigger, i) => {
    const isSelected = trigger.value === value
    const padded = ` ${trigger.label} `

    const style = isSelected
      ? focused
        ? textStyle({ bold: true, fg: theme.background, bg: color })
        : textStyle({ bold: true, fg: theme.background, bg: theme.muted, dim: true })
      : focused
        ? textStyle({ fg: theme.foreground })
        : textStyle({ dim: true, fg: theme.muted })

    if (i > 0) {
      parts.push(
        <span key={`div-${i}`} style={textStyle({ dim: true, fg: theme.muted })}>│</span>,
      )
    }

    parts.push(
      <span key={`opt-${i}`} style={style}>
        {padded}
      </span>,
    )
  })

  return (
    <box flexDirection="column">
      <text>{parts}</text>
      {separator && (
        <text wrapMode="none" style={textStyle({ dim: true, fg: theme.muted })}>
          {"─".repeat(200)}
        </text>
      )}
    </box>
  )
}

// ── TabsTrigger ──────────────────────────────────────────────────────────

export interface TabsTriggerProps {
  /** Unique value that links this trigger to its TabsContent. */
  value: string
  children: ReactNode
}

/**
 * Declares a tab trigger. Does not render anything itself —
 * TabsList reads the value and children props to build the tab bar.
 */
export function TabsTrigger(_props: TabsTriggerProps) {
  return null
}

// ── TabsContent ──────────────────────────────────────────────────────────

export interface TabsContentProps {
  /** The value that must match the active tab for this content to render. */
  value: string
  children: ReactNode
}

/** Renders children only when its value matches the active tab. */
export function TabsContent({ value, children }: TabsContentProps) {
  const { value: activeValue } = useTabsContext()
  if (activeValue !== value) return null
  return <>{children}</>
}

// ── Legacy TabBar (simple API) ───────────────────────────────────────────

export interface TabBarProps {
  /** Text label shown before the options. */
  label?: string
  /** Array of option strings to display. */
  options: string[]
  /** Zero-based index of the currently selected option. */
  selectedIndex: number
  /** Whether the tab bar appears focused. */
  focused?: boolean
  /** The foreground color applied to the selected option when focused. */
  activeColor?: string
  /** Whether to show the horizontal separator below tabs. */
  separator?: boolean
  /** Keyboard handler — pass useKeyboard from @gridland/utils */
  useKeyboard?: (handler: (event: any) => void) => void
}

/** Simple tab bar API wrapping the compound Tabs components. */
export function TabBar({
  label,
  options,
  selectedIndex,
  focused = true,
  activeColor,
  separator = true,
  useKeyboard,
}: TabBarProps) {
  return (
    <Tabs value={options[selectedIndex]}>
      <TabsList label={label} focused={focused} activeColor={activeColor} separator={separator} useKeyboard={useKeyboard}>
        {options.map((option) => (
          <TabsTrigger key={option} value={option}>
            {option}
          </TabsTrigger>
        ))}
      </TabsList>
    </Tabs>
  )
}

// @ts-nocheck
import { createContext, useContext, Children, isValidElement, Fragment } from "react"
import type { ReactNode, ReactElement } from "react"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"

// ── Types ────────────────────────────────────────────────────────────────

type Scalar = string | number | boolean | null | undefined
export type ScalarDict = { [key: string]: Scalar }

// ── Context ──────────────────────────────────────────────────────────────

interface TableContextValue {
  columnWidths: number[]
  padding: number
  headerColor: string
  borderColor: string
  foregroundColor: string
}

const TableContext = createContext<TableContextValue | null>(null)

function useTableContext() {
  const ctx = useContext(TableContext)
  if (!ctx) throw new Error("Table compound components must be used within <TableRoot>")
  return ctx
}

// ── Utility functions ────────────────────────────────────────────────────

export function getColumns<T extends ScalarDict>(
  data: T[],
  columnsProp?: (keyof T)[],
): (keyof T)[] {
  if (columnsProp) return columnsProp
  const keys = new Set<keyof T>()
  for (const row of data) {
    for (const key in row) keys.add(key)
  }
  return Array.from(keys)
}

export interface ColumnInfo<T> {
  field: keyof T
  width: number
}

export function calculateColumnWidths<T extends ScalarDict>(
  columns: (keyof T)[],
  data: T[],
  padding: number,
): ColumnInfo<T>[] {
  return columns.map((field) => {
    const headerWidth = String(field).length
    const maxDataWidth = data.reduce((max, row) => {
      const val = row[field]
      return Math.max(max, val == null ? 0 : String(val).length)
    }, 0)
    return { field, width: Math.max(headerWidth, maxDataWidth) + padding * 2 }
  })
}

export function padCell(value: string, width: number, padding: number, align: "left" | "right" | "center" = "left"): string {
  if (align === "right") {
    const leftPad = width - value.length - padding
    return " ".repeat(Math.max(0, leftPad)) + value + " ".repeat(padding)
  }
  if (align === "center") {
    const totalGap = width - value.length
    const leftGap = Math.floor(totalGap / 2)
    const rightGap = totalGap - leftGap
    return " ".repeat(Math.max(0, leftGap)) + value + " ".repeat(Math.max(0, rightGap))
  }
  const rightPad = width - value.length - padding
  return " ".repeat(padding) + value + " ".repeat(Math.max(0, rightPad))
}

// ── Helpers: extract cell text from React tree ───────────────────────────

function extractCellText(node: ReactNode): string {
  if (node == null) return ""
  if (typeof node === "string") return node
  if (typeof node === "number" || typeof node === "boolean") return String(node)
  if (Array.isArray(node)) return node.map(extractCellText).join("")
  if (isValidElement(node)) return extractCellText((node as ReactElement<{ children?: ReactNode }>).props.children)
  return ""
}

function collectColumnWidths(children: ReactNode, padding: number): number[] {
  const columnMaxWidths: number[] = []

  Children.forEach(children, (section) => {
    if (!isValidElement(section)) return
    if (section.type === TableCaption) return

    Children.forEach(section.props.children, (row: ReactNode) => {
      if (!isValidElement(row)) return

      let colIdx = 0
      Children.forEach(row.props.children, (cell: ReactNode) => {
        if (!isValidElement(cell)) return
        const span = cell.props.colSpan ?? 1
        if (span === 1) {
          const text = extractCellText(cell.props.children)
          const width = text.length + padding * 2
          if (colIdx >= columnMaxWidths.length) {
            columnMaxWidths.push(width)
          } else {
            columnMaxWidths[colIdx] = Math.max(columnMaxWidths[colIdx], width)
          }
        }
        colIdx += span
      })
    })
  })

  return columnMaxWidths
}

function getTotalWidth(columnWidths: number[]): number {
  if (columnWidths.length === 0) return 0
  return columnWidths.reduce((sum, w) => sum + w, 0) + (columnWidths.length - 1)
}

// ── TableRoot (compound root) ────────────────────────────────────────────

export interface TableRootProps {
  /** Table sub-components (TableHeader, TableBody, TableFooter, TableCaption). */
  children: ReactNode
  /** Cell padding in characters. @default 1 */
  padding?: number
  /** Override header text color. Defaults to theme.foreground. */
  headerColor?: string
  /** Override border/separator color. Defaults to theme.muted. */
  borderColor?: string
}

/** Compound table root — auto-calculates column widths from all header and body cells. */
export function TableRoot({ children, padding = 1, headerColor, borderColor }: TableRootProps) {
  const theme = useTheme()
  const resolvedHeaderColor = headerColor ?? theme.foreground
  const resolvedBorderColor = borderColor ?? theme.muted

  const columnWidths = collectColumnWidths(children, padding)

  return (
    <TableContext.Provider
      value={{
        columnWidths,
        padding,
        headerColor: resolvedHeaderColor,
        borderColor: resolvedBorderColor,
        foregroundColor: theme.foreground,
      }}
    >
      <box>{children}</box>
    </TableContext.Provider>
  )
}

// ── TableHeader ──────────────────────────────────────────────────────────

export interface TableHeaderProps {
  children: ReactNode
}

/** Table header section. Renders a horizontal rule below its rows. */
export function TableHeader({ children }: TableHeaderProps) {
  const ctx = useTableContext()
  const totalWidth = getTotalWidth(ctx.columnWidths)

  return (
    <box>
      {children}
      <text>
        <span style={textStyle({ fg: ctx.borderColor })}>{"\u2500".repeat(totalWidth)}</span>
      </text>
    </box>
  )
}

// ── TableBody ────────────────────────────────────────────────────────────

export interface TableBodyProps {
  children: ReactNode
}

/** Table body section. Renders dim separators between rows. */
export function TableBody({ children }: TableBodyProps) {
  const ctx = useTableContext()
  const totalWidth = getTotalWidth(ctx.columnWidths)
  const rows = Children.toArray(children)

  return (
    <box>
      {rows.map((row, index) => (
        <Fragment key={index}>
          {row}
          {index < rows.length - 1 && (
            <text>
              <span style={textStyle({ fg: ctx.borderColor, dim: true })}>
                {"\u2500".repeat(totalWidth)}
              </span>
            </text>
          )}
        </Fragment>
      ))}
    </box>
  )
}

// ── TableFooter ──────────────────────────────────────────────────────────

export interface TableFooterProps {
  children: ReactNode
}

/** Table footer section. Renders a horizontal rule above its rows. */
export function TableFooter({ children }: TableFooterProps) {
  const ctx = useTableContext()
  const totalWidth = getTotalWidth(ctx.columnWidths)

  return (
    <box>
      <text>
        <span style={textStyle({ fg: ctx.borderColor })}>{"\u2500".repeat(totalWidth)}</span>
      </text>
      {children}
    </box>
  )
}

// ── TableRow ─────────────────────────────────────────────────────────────

export interface TableRowProps {
  children: ReactNode
}

/** Renders a single row of padded, aligned cells. */
export function TableRow({ children }: TableRowProps) {
  const ctx = useTableContext()
  const parts: ReactNode[] = []
  let colIdx = 0

  Children.forEach(children, (child) => {
    if (!isValidElement(child)) return

    const text = extractCellText(child.props.children)
    const span = child.props.colSpan ?? 1
    const align = child.props.align ?? "left"
    const cellColor = child.props.color
    const isHead = child.type === TableHead

    // Calculate width (accounting for colSpan)
    let spanWidth = 0
    for (let i = 0; i < span && (colIdx + i) < ctx.columnWidths.length; i++) {
      spanWidth += ctx.columnWidths[colIdx + i]
      if (i > 0) spanWidth += 1
    }
    if (spanWidth === 0) spanWidth = text.length + ctx.padding * 2

    const padded = padCell(text, spanWidth, ctx.padding, align)

    if (colIdx > 0) {
      parts.push(
        <span key={`sep-${colIdx}`} style={textStyle({ fg: ctx.borderColor, dim: true })}>
          {" "}
        </span>,
      )
    }

    const color = cellColor ?? (isHead ? ctx.headerColor : ctx.foregroundColor)
    const dim = !isHead && !cellColor

    parts.push(
      <span key={`cell-${colIdx}`} style={textStyle({ fg: color, dim })}>
        {padded}
      </span>,
    )

    colIdx += span
  })

  return <text>{parts}</text>
}

// ── TableHead ────────────────────────────────────────────────────────────

export interface TableHeadProps {
  children: ReactNode
  /** Text alignment within the cell. @default "left" */
  align?: "left" | "right" | "center"
  /** Override text color for this header cell. */
  color?: string
  /** Number of columns this cell should span. @default 1 */
  colSpan?: number
}

/**
 * Declares a header cell. Does not render itself —
 * TableRow reads the children prop to build the styled row.
 */
export function TableHead(_props: TableHeadProps) {
  return null
}

// ── TableCell ────────────────────────────────────────────────────────────

export interface TableCellProps {
  children: ReactNode
  /** Text alignment within the cell. @default "left" */
  align?: "left" | "right" | "center"
  /** Override text color for this body cell. */
  color?: string
  /** Number of columns this cell should span. @default 1 */
  colSpan?: number
}

/**
 * Declares a body cell. Does not render itself —
 * TableRow reads the children prop to build the styled row.
 */
export function TableCell(_props: TableCellProps) {
  return null
}

// ── TableCaption ─────────────────────────────────────────────────────────

export interface TableCaptionProps {
  children: ReactNode
}

/** Dim caption text rendered outside the table grid. */
export function TableCaption({ children }: TableCaptionProps) {
  const ctx = useTableContext()
  return (
    <text>
      <span style={textStyle({ fg: ctx.borderColor, dim: true })}>
        {extractCellText(children)}
      </span>
    </text>
  )
}

// ── Table (data-driven convenience wrapper) ────────────────────────

export interface TableProps<T extends ScalarDict> {
  /** Array of row objects to display. */
  data: T[]
  /** Ordered subset of keys to show as columns. Defaults to all keys. */
  columns?: (keyof T)[]
  /** Cell padding in characters. @default 1 */
  padding?: number
  /** Override header text color. Defaults to theme.foreground. */
  headerColor?: string
  /** Override border/separator color. Defaults to theme.muted. */
  borderColor?: string
}

/** Data-driven table — pass an array of objects and get a formatted table. */
export function Table<T extends ScalarDict>({
  data,
  columns: columnsProp,
  padding = 1,
  headerColor,
  borderColor,
}: TableProps<T>) {
  const cols = getColumns(data, columnsProp)

  return (
    <TableRoot padding={padding} headerColor={headerColor} borderColor={borderColor}>
      <TableHeader>
        <TableRow>
          {cols.map((col) => (
            <TableHead key={String(col)}>{String(col)}</TableHead>
          ))}
        </TableRow>
      </TableHeader>
      <TableBody>
        {data.map((row, index) => (
          <TableRow key={index}>
            {cols.map((col) => (
              <TableCell key={String(col)}>
                {row[col] == null ? "" : String(row[col])}
              </TableCell>
            ))}
          </TableRow>
        ))}
      </TableBody>
    </TableRoot>
  )
}

import type { ReactNode } from "react"

export interface TerminalWindowProps {
  /** Content rendered inside the window below the title bar. */
  children: ReactNode
  /** Additional CSS classes applied to the outermost container. */
  className?: string
  /** Text displayed centered in the title bar. */
  title?: string
  /** Minimum width of the window. Applied as inline style. */
  minWidth?: number | string
  /** When true, the window background is transparent. Defaults to false (dark gray). */
  transparent?: boolean
  /** Callback fired when the red (close) button is clicked. */
  onClose?: () => void
  /** Callback fired when the yellow (minimize) button is clicked. */
  onMinimize?: () => void
  /** Callback fired when the green (maximize) button is clicked. */
  onMaximize?: () => void
}

function cn(...classes: (string | undefined | false)[]): string {
  return classes.filter(Boolean).join(" ")
}

/** macOS-style window chrome with traffic-light buttons and title bar. Web/HTML component for docs and demos. */
export function TerminalWindow({
  children,
  className,
  title,
  minWidth,
  transparent = false,
  onClose,
  onMinimize,
  onMaximize,
}: TerminalWindowProps) {
  return (
    <div
      className={cn(
        "rounded-2xl border shadow-lg overflow-hidden",
        className,
      )}
      style={{
        ...(minWidth != null ? { minWidth } : {}),
        ...(transparent ? {} : { backgroundColor: "#1e1e2e" }),
      }}
    >
      {/* Title Bar */}
      <div
        className="grid grid-cols-3 items-center px-3 py-2.5 border-b"
        style={transparent ? {} : { backgroundColor: "#2a2a3c", borderColor: "#313244" }}
      >
        {/* Traffic Light Buttons */}
        <div className="flex gap-2">
          <button
            onClick={onClose}
            className="w-3 h-3 bg-red-500 hover:bg-red-600 rounded-full transition-colors"
            aria-label="Close"
            type="button"
          />
          <button
            onClick={onMinimize}
            className="w-3 h-3 bg-yellow-500 hover:bg-yellow-600 rounded-full transition-colors"
            aria-label="Minimize"
            type="button"
          />
          <button
            onClick={onMaximize}
            className="w-3 h-3 bg-green-500 hover:bg-green-600 rounded-full transition-colors"
            aria-label="Maximize"
            type="button"
          />
        </div>
        {/* Title */}
        {title && (
          <div
            className="text-center text-sm select-none"
            style={transparent ? {} : { color: "#a6adc8" }}
          >
            {title}
          </div>
        )}
        {/* Empty right column for balance */}
        <div />
      </div>
      {/* Content */}
      <div className="overflow-hidden">{children}</div>
    </div>
  )
}

// @ts-nocheck — OpenTUI intrinsic elements conflict with React's HTML/SVG types
import { textStyle } from './text-style'
import { useTheme } from './theme'

export interface TextInputProps {
  /** Field label shown above the input */
  label?: string
  /** Helper text shown inline next to the label */
  description?: string
  /** Error message — overrides description when set */
  error?: string
  /** Whether the field is required (shows indicator on label) */
  required?: boolean
  /** Whether the input is disabled */
  disabled?: boolean
  /** Current value of the input */
  value: string
  /** Called on every keystroke */
  onChange?: (value: string) => void
  /** Called when Enter is pressed */
  onSubmit?: (value: string) => void
  /** Hint text shown when empty */
  placeholder?: string
  /** Prompt string shown before the input (e.g. "> ") */
  prompt?: string
  /** Whether the input is focused and accepting keystrokes */
  focus?: boolean
  /** Maximum characters allowed */
  maxLength?: number
}

/** Form text input with label, validation, and controlled mode. */
export function TextInput({ label, description, error, required = false, disabled = false, value, onChange, onSubmit, placeholder, prompt, focus = false, maxLength }: TextInputProps) {
  const theme = useTheme()
  const isFocused = focus && !disabled

  const empty = !value
  const showLabel = label != null
  const message = error ?? description

  return (
    <box flexDirection="column">
      {showLabel && (
        <text>
          <span style={textStyle({ fg: error ? theme.error : isFocused ? theme.primary : disabled ? theme.muted : theme.foreground, bold: !disabled, dim: disabled })}>
            {isFocused ? '\u25B8 ' : '  '}
            {label}
          </span>
          {required && <span style={textStyle({ fg: theme.error })}>{' *'}</span>}
          {value && maxLength != null && (
            <span style={textStyle({ dim: true, fg: theme.muted })}>
              {' '}
              {value.length}/{maxLength}
            </span>
          )}
          {message != null && (
            <span style={textStyle({ fg: error ? theme.error : theme.muted, dim: !error })}>
              {' | '}
              {message}
            </span>
          )}
        </text>
      )}
      <box flexDirection="row" marginLeft={showLabel ? 2 : 0}>
        {prompt != null && <text style={{ fg: error ? theme.error : isFocused ? theme.primary : theme.muted }}>{prompt}</text>}
        {isFocused ? (
          <input
            value={value}
            placeholder={placeholder}
            maxLength={maxLength}
            focused
            onInput={onChange}
            onSubmit={onSubmit}
            cursorColor={error ? theme.error : theme.muted}
            cursorStyle={{ style: "line", blinking: empty }}
            placeholderColor={theme.placeholder}
            textColor={theme.foreground}
          />
        ) : (
          <text style={{ fg: empty ? theme.placeholder : disabled ? theme.muted : theme.foreground, dim: disabled }}>{empty ? placeholder : value}</text>
        )}
      </box>
    </box>
  )
}

// @ts-nocheck
import { createContext, memo, useCallback, useContext, useEffect, useMemo, useState } from "react"
import type { ReactNode } from "react"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"
import type { Theme } from "./theme"

// ── Constants ──────────────────────────────────────────────────────

const DOTS = ["⠋", "⠙", "⠹", "⠸", "⠼", "⠴", "⠦", "⠧", "⠇", "⠏"] as const
const SPINNER_INTERVAL = 80

// ── Step data type (for data-driven usage) ─────────────────────────

export interface ChainOfThoughtStepData {
  /** Primary label for the step. */
  label: string
  /** Secondary detail shown dimmed after the label. */
  description?: string
  /** Current status. */
  status: "done" | "running" | "pending" | "error"
  /** Custom icon character. */
  icon?: string
  /** Output text shown below the step. */
  output?: string
}

/** @deprecated Use ChainOfThoughtStepData instead. */
export type Step = ChainOfThoughtStepData

// ── Controllable state helper ──────────────────────────────────────

function useControllableOpen(
  controlledOpen: boolean | undefined,
  defaultOpen: boolean,
  onOpenChange: ((open: boolean) => void) | undefined,
): [boolean, (open: boolean) => void] {
  const [internalOpen, setInternalOpen] = useState(defaultOpen)
  const isOpen = controlledOpen ?? internalOpen
  const setOpen = useCallback((value: boolean) => {
    if (controlledOpen === undefined) setInternalOpen(value)
    onOpenChange?.(value)
  }, [controlledOpen, onOpenChange])
  return [isOpen, setOpen]
}

// ── Context ────────────────────────────────────────────────────────

interface ChainOfThoughtContextValue {
  isOpen: boolean
  setIsOpen: (open: boolean) => void
}

const ChainOfThoughtContext = createContext<ChainOfThoughtContextValue | null>(null)

export const useChainOfThought = () => {
  const context = useContext(ChainOfThoughtContext)
  if (!context) {
    throw new Error("ChainOfThought components must be used within <ChainOfThought>")
  }
  return context
}

// ── Status helper ──────────────────────────────────────────────────

function getStepColor(status: string, theme: Theme): string {
  switch (status) {
    case "done": return theme.success
    case "running": return theme.primary
    case "pending": return theme.muted
    case "error": return theme.error
    default: return theme.muted
  }
}

// ── ChainOfThought (root) ──────────────────────────────────────────

export interface ChainOfThoughtProps {
  /** Controlled open state. */
  open?: boolean
  /** Default open state (uncontrolled). Defaults to false. */
  defaultOpen?: boolean
  /** Called when the open state changes. */
  onOpenChange?: (open: boolean) => void
  children: ReactNode
}

/** Collapsible chain-of-thought container with controlled or uncontrolled open state. */
export const ChainOfThought = memo(({
  open,
  defaultOpen = false,
  onOpenChange,
  children,
}: ChainOfThoughtProps) => {
  const [isOpen, setIsOpen] = useControllableOpen(open, defaultOpen, onOpenChange)

  const context = useMemo(
    () => ({ isOpen, setIsOpen }),
    [isOpen, setIsOpen],
  )

  return (
    <ChainOfThoughtContext.Provider value={context}>
      <box flexDirection="column">
        {children}
      </box>
    </ChainOfThoughtContext.Provider>
  )
})

// ── ChainOfThoughtHeader ───────────────────────────────────────────

export interface ChainOfThoughtHeaderProps {
  /** Duration string shown after the label (e.g. "3.2s"). */
  duration?: string
  /** Header label content. Defaults to "Thought for". */
  children?: ReactNode
}

/** Header row with collapse arrow and optional duration label. */
export const ChainOfThoughtHeader = memo(({
  duration,
  children = "Thought for",
}: ChainOfThoughtHeaderProps) => {
  const theme = useTheme()
  const { isOpen } = useChainOfThought()
  const arrow = isOpen ? "▼" : "▶"

  return (
    <text>
      <span style={textStyle({ fg: theme.muted })}>{arrow}</span>
      <span style={textStyle({ dim: true, fg: theme.muted })}>{" "}{children}{duration ? " " + duration : ""}</span>
    </text>
  )
})

// ── ChainOfThoughtContent ──────────────────────────────────────────

export interface ChainOfThoughtContentProps {
  children: ReactNode
}

/** Content region that renders only when the chain is open. */
export const ChainOfThoughtContent = memo(({ children }: ChainOfThoughtContentProps) => {
  const { isOpen } = useChainOfThought()
  if (!isOpen) return null
  return <>{children}</>
})

// ── ChainOfThoughtStep ─────────────────────────────────────────────

export interface ChainOfThoughtStepProps {
  /** Primary label for the step. */
  label: string
  /** Secondary detail shown dimmed after the label. */
  description?: string
  /** Current status. Defaults to "done". */
  status?: "done" | "running" | "pending" | "error"
  /** Custom icon character. Defaults to status-based dot (● done, ○ pending, animated running). */
  icon?: string
  /** @deprecated Will be auto-detected in a future version. Safe to continue using. */
  isLast?: boolean
  /** Output content rendered below the step with a pipe gutter. */
  children?: ReactNode
}

/** Individual step with status icon, label, and optional output content. */
export const ChainOfThoughtStep = memo(({
  label,
  description,
  status = "done",
  icon,
  isLast = false,
  children,
}: ChainOfThoughtStepProps) => {
  const theme = useTheme()
  const isActive = status === "running"
  const isPending = status === "pending"
  const color = getStepColor(status, theme)
  const pipe = "│"

  // Self-contained spinner animation — only ticks when this step is active
  const [frame, setFrame] = useState(0)
  useEffect(() => {
    if (!isActive) { setFrame(0); return }
    const id = setInterval(() => setFrame(f => f + 1), SPINNER_INTERVAL)
    return () => clearInterval(id)
  }, [isActive])

  const dot = icon ?? (isActive
    ? DOTS[frame % DOTS.length]!
    : isPending ? "○" : "●")

  return (
    <box flexDirection="column" marginLeft={1}>
      <text>
        <span style={textStyle({ fg: color })}>{dot}</span>
        <span style={textStyle({ fg: theme.foreground })}>{" "}</span>
        <span style={textStyle({ fg: isPending ? theme.muted : color, dim: isPending, bold: isActive })}>{label}</span>
        {description && <span style={textStyle({ dim: true, fg: theme.muted })}>{" — " + description}</span>}
      </text>
      {children && (
        <text>
          <span style={textStyle({ fg: color, dim: true })}>{pipe + "  "}</span>
          <span style={textStyle({ fg: status === "error" ? theme.error : theme.accent })}>{children}</span>
        </text>
      )}
      {!isLast && (
        <text>
          <span style={textStyle({ fg: color, dim: true })}>{pipe}</span>
        </text>
      )}
    </box>
  )
})

// ── Display names ──────────────────────────────────────────────────

ChainOfThought.displayName = "ChainOfThought"
ChainOfThoughtHeader.displayName = "ChainOfThoughtHeader"
ChainOfThoughtContent.displayName = "ChainOfThoughtContent"
ChainOfThoughtStep.displayName = "ChainOfThoughtStep"

// @ts-nocheck — OpenTUI intrinsic elements conflict with React's HTML/SVG types
import { useState, useRef, useCallback, useEffect, type ReactNode } from "react"
import {
  useFocus,
  FocusProvider,
  FocusScope,
  useKeyboard,
  useShortcuts,
  useFocusedShortcuts,
} from "@gridland/utils"
import { StatusBar } from "./status-bar"
import { textStyle } from "./text-style"
import { useTheme } from "./theme"

// ── Types ─────────────────────────────────────────────────────────────

export interface SideNavItem {
  /** Unique identifier for this nav item. */
  id: string
  /** Display label shown in the sidebar. */
  name: string
  /** Optional text appended after the item name. */
  suffix?: string
}

export interface SideNavProps {
  /** List of navigable items. */
  items: SideNavItem[]
  /** Width of the sidebar in columns. @default 20 */
  sidebarWidth?: number
  /** Optional title displayed above the sidebar. */
  title?: string
  /**
   * Render the main panel content for the active item.
   * Receives the active item, whether the user has selected it for interaction,
   * and a captureKeyboard callback for routing keyboard events.
   */
  children: (ctx: {
    activeItem: SideNavItem
    isInteracting: boolean
    captureKeyboard: (handler: (event: any) => void) => void
  }) => ReactNode
  /** Show the status bar at the bottom. @default true */
  showStatusBar?: boolean
  /** Show the active item name as a header in the main panel. @default true */
  showHeader?: boolean
  /**
   * Programmatically switch the active item by ID. When this changes to a new
   * value that matches an item in the list, the nav switches to that item.
   * User navigation via arrow keys always overrides this after it fires.
   */
  requestedActiveId?: string
}

// ── NavItem ───────────────────────────────────────────────────────────

function NavItemRow({ item, autoFocus, onFocus, onSelectChange, handlerRef }: {
  item: SideNavItem
  autoFocus?: boolean
  onFocus: () => void
  onSelectChange: (selected: boolean) => void
  handlerRef: React.MutableRefObject<((event: any) => void) | null>
}) {
  const theme = useTheme()
  const { isFocused, isSelected, focusId, focusRef } = useFocus({ id: item.id, autoFocus })

  useEffect(() => {
    if (isFocused) onFocus()
  }, [isFocused])

  useEffect(() => {
    onSelectChange(isSelected)
  }, [isSelected])

  useKeyboard((event) => {
    handlerRef.current?.(event)
  }, { focusId, selectedOnly: true })

  useShortcuts(
    isSelected
      ? [{ key: "esc", label: "back" }]
      : [{ key: "↑↓", label: "navigate" }, { key: "enter", label: "select" }],
    focusId,
  )

  const fg = isSelected ? theme.focusSelected
    : isFocused ? theme.focusFocused
    : theme.muted

  return (
    <box ref={focusRef} height={1} paddingX={1}>
      <text style={textStyle({ fg, bold: isFocused || isSelected })}>
        {isFocused || isSelected ? "▸" : " "} {item.name}{item.suffix && ` ${item.suffix}`}
      </text>
    </box>
  )
}

// ── SideNavStatusBar ──────────────────────────────────────────────────

function SideNavStatusBar() {
  const shortcuts = useFocusedShortcuts()
  return (
    <box paddingX={1} paddingBottom={1}>
      <StatusBar items={shortcuts} />
    </box>
  )
}

// ── SideNav ───────────────────────────────────────────────────────────

/** Two-panel layout with a keyboard-navigable sidebar and a main content area. */
export function SideNav({
  items,
  sidebarWidth = 20,
  title,
  children,
  showStatusBar = true,
  showHeader = true,
  requestedActiveId,
}: SideNavProps) {
  const theme = useTheme()
  const [activeIndex, setActiveIndex] = useState(0)
  const [isInteracting, setIsInteracting] = useState(false)
  const handlerRef = useRef<((event: any) => void) | null>(null)
  const lastRequestedActiveIdRef = useRef<string | undefined>()
  // Tracks which nav item triggered the interaction, decoupled from activeIndex.
  // Without this, changing activeIndex programmatically breaks the isInteracting
  // update when that original item deselects (e.g. on Esc).
  const interactingItemIdRef = useRef<string | null>(null)

  // Switch active item when requestedActiveId changes to a new value.
  // Uses a ref to avoid re-processing the same ID if items re-render.
  useEffect(() => {
    if (!requestedActiveId || requestedActiveId === lastRequestedActiveIdRef.current) return
    lastRequestedActiveIdRef.current = requestedActiveId
    const idx = items.findIndex(item => item.id === requestedActiveId)
    if (idx !== -1) setActiveIndex(idx)
  }, [requestedActiveId, items])

  const captureKeyboard = useCallback((handler: (event: any) => void) => {
    handlerRef.current = handler
  }, [])

  const activeItem = items[activeIndex]

  return (
    <FocusProvider selectable>
      <box flexDirection="row" flexGrow={1}>
        {/* Sidebar — full height with right divider */}
        <box flexDirection="column" width={sidebarWidth} border={["right"]} borderColor={theme.borderMuted}>
          {title && (
            <box paddingX={2} paddingTop={1}>
              <text style={textStyle({ bold: true, fg: theme.focusFocused })}>
                {title}
              </text>
            </box>
          )}
          <box flexDirection="column" paddingTop={1}>
            {items.map((item, i) => (
              <NavItemRow
                key={item.id}
                item={item}
                autoFocus={i === 0}
                onFocus={() => setActiveIndex(i)}
                onSelectChange={(selected) => {
                  if (selected) {
                    interactingItemIdRef.current = item.id
                    setIsInteracting(true)
                  } else if (interactingItemIdRef.current === item.id) {
                    interactingItemIdRef.current = null
                    setIsInteracting(false)
                  }
                }}
                handlerRef={handlerRef}
              />
            ))}
          </box>
        </box>

        {/* Main panel */}
        <box flexDirection="column" flexGrow={1}>
          <box flexDirection="column" flexGrow={1} paddingTop={1} overflow="hidden">
            <box
              flexDirection="column"
              flexGrow={1}
              overflow="hidden"
            >
              {showHeader && (
                <box paddingX={1}>
                  <text style={textStyle({ bold: true, fg: theme.focusSelected })}>
                    {activeItem.name}
                  </text>
                </box>
              )}
              {isInteracting ? (
                <FocusScope trap selectable autoFocus autoSelect restoreOnUnmount>
                  {children({ activeItem, isInteracting, captureKeyboard })}
                </FocusScope>
              ) : (
                children({ activeItem, isInteracting, captureKeyboard })
              )}
            </box>
          </box>
          {showStatusBar && <SideNavStatusBar />}
        </box>
      </box>
    </FocusProvider>
  )
}
